package com.bank.logic;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import java.util.List;

/**
 * Unit tests for SavingsAccount focusing on 100% coverage and edge-case analysis.
 */
class SavingsAccountTest {

    @Test
    @DisplayName("Single-arg constructor → initializes with default interest rate and valid history")
    void constructor_SingleArg_SetsDefaultInterestRate() {
        // Arrange
        double initialBalance = 500.0;
        double expectedDefaultRate = 0.02;

        // Act
        SavingsAccount account = new SavingsAccount(initialBalance);

        // Assert
        assertEquals(initialBalance, account.getBalance());
        assertEquals(expectedDefaultRate, account.getInterestRate());
        assertEquals(1, account.getHistory().size());
        assertTrue(account.getHistory().get(0).contains("Account opened with: 500.0"));
    }

    @Test
    @DisplayName("Dual-arg constructor → initializes with custom values")
    void constructor_DualArg_SetsCustomValues() {
        // Arrange
        double initialBalance = 1000.0;
        double interestRate = 0.05;

        // Act
        SavingsAccount account = new SavingsAccount(initialBalance, interestRate);

        // Assert
        assertEquals(initialBalance, account.getBalance());
        assertEquals(interestRate, account.getInterestRate());
    }

    @Test
    @DisplayName("Constructor with negative balance → throws IllegalArgumentException")
    void constructor_NegativeBalance_ThrowsException() {
        // Arrange
        double initialBalance = -1.0;
        double interestRate = 0.02;

        // Act & Assert
        assertThrows(IllegalArgumentException.class, () -> new SavingsAccount(initialBalance, interestRate));
    }

    @Test
    @DisplayName("Constructor with negative interest rate → throws IllegalArgumentException")
    void constructor_NegativeInterest_ThrowsException() {
        // Arrange
        double initialBalance = 100.0;
        double interestRate = -0.01;

        // Act & Assert
        assertThrows(IllegalArgumentException.class, () -> new SavingsAccount(initialBalance, interestRate));
    }

    @Test
    @DisplayName("Constructor with zero values → creates account successfully")
    void constructor_ZeroValues_Success() {
        // Arrange & Act
        SavingsAccount account = new SavingsAccount(0, 0);

        // Assert
        assertEquals(0.0, account.getBalance());
        assertEquals(0.0, account.getInterestRate());
    }

    @Test
    @DisplayName("processTransaction with positive amount → increases balance")
    void processTransaction_PositiveAmount_IncreasesBalance() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0);
        double deposit = 50.0;

        // Act
        account.processTransaction(deposit);

        // Assert
        assertEquals(150.0, account.getBalance());
    }

    @Test
    @DisplayName("processTransaction with negative amount within balance → decreases balance")
    void processTransaction_NegativeAmountWithinBalance_DecreasesBalance() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0);
        double withdrawal = -40.0;

        // Act
        account.processTransaction(withdrawal);

        // Assert
        assertEquals(60.0, account.getBalance());
    }

    @Test
    @DisplayName("processTransaction with negative amount equal to balance → results in zero balance")
    void processTransaction_WithdrawAll_ResultsInZero() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0);
        double withdrawal = -100.0;

        // Act
        account.processTransaction(withdrawal);

        // Assert
        assertEquals(0.0, account.getBalance());
    }

    @Test
    @DisplayName("processTransaction with withdrawal exceeding balance → throws InsolventException")
    void processTransaction_ExceedingBalance_ThrowsInsolventException() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0);
        double withdrawal = -100.01;

        // Act & Assert
        assertThrows(InsolventException.class, () -> account.processTransaction(withdrawal));
    }

    @Test
    @DisplayName("applyInterest → correctly calculates interest and updates balance and history")
    void applyInterest_UpdatesBalanceAndHistory() {
        // Arrange
        double initialBalance = 1000.0;
        double interestRate = 0.05; // 5%
        SavingsAccount account = new SavingsAccount(initialBalance, interestRate);
        double expectedInterest = 50.0;
        double expectedBalance = 1050.0;

        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalance, account.getBalance());
        List<String> history = account.getHistory();
        assertEquals(2, history.size());
        assertEquals("Interest applied: 50.00", history.get(1));
    }

    @Test
    @DisplayName("applyInterest with zero balance → balance remains zero and interest is 0.00")
    void applyInterest_ZeroBalance_NoIncrease() {
        // Arrange
        SavingsAccount account = new SavingsAccount(0.0, 0.05);

        // Act
        account.applyInterest();

        // Assert
        assertEquals(0.0, account.getBalance());
        assertEquals("Interest applied: 0.00", account.getHistory().get(1));
    }

    @Test
    @DisplayName("getAccountSummary → returns correctly formatted string")
    void getAccountSummary_ReturnsFormattedString() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0, 0.02);
        account.processTransaction(50.0); // Trans 1: Open, Trans 2: Deposit
        String expected = "Balance: 150.00 | Transactions: 2";

        // Act
        String summary = account.getAccountSummary();

        // Assert
        assertEquals(expected, summary);
    }

    @Test
    @DisplayName("getHistory → returns immutable copy of history list")
    void getHistory_ReturnsUnmodifiableList() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0);
        List<String> history = account.getHistory();

        // Act & Assert
        assertThrows(UnsupportedOperationException.class, () -> history.add("Unauthorized entry"));
    }

    @Test
    @DisplayName("toString → returns correctly formatted representation")
    void toString_ReturnsFormattedString() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0, 0.02);
        String expected = "SavingsAccount{balance=100.0, interestRate=0.02}";

        // Act
        String result = account.toString();

        // Assert
        assertEquals(expected, result);
    }

    @Test
    @DisplayName("processTransaction with zero → state remains unchanged")
    void processTransaction_ZeroAmount_NoChange() {
        // Arrange
        SavingsAccount account = new SavingsAccount(100.0);

        // Act
        account.processTransaction(0);

        // Assert
        assertEquals(100.0, account.getBalance());
    }

    @Test
    @DisplayName("Large values transaction → handles large doubles correctly")
    void processTransaction_LargeValues_CorrectBalance() {
        // Arrange
        SavingsAccount account = new SavingsAccount(1_000_000.0);
        double largeDeposit = 9_000_000.0;

        // Act
        account.processTransaction(largeDeposit);

        // Assert
        assertEquals(10_000_000.0, account.getBalance());
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class SavingsAccountTest {

    private static final double INITIAL_BALANCE = 1000.0;
    private static final double INTEREST_RATE = 0.05;
    private static final double DELTA = 0.001;

    private SavingsAccount account;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(INITIAL_BALANCE, INTEREST_RATE);
    }

    @Test
    @DisplayName("Constructor with initial balance → sets default interest rate and logs history")
    void constructorOneArg_setsDefaultsAndLogsHistory() {
        // Arrange & Act
        SavingsAccount defaultAccount = new SavingsAccount(500.0);

        // Assert
        assertEquals(500.0, defaultAccount.getBalance(), DELTA);
        assertEquals(0.02, defaultAccount.getInterestRate(), DELTA);
        List<String> history = defaultAccount.getHistory();
        assertEquals(1, history.size());
        assertEquals("Account opened with: 500.0", history.get(0));
    }

    @Test
    @DisplayName("Constructor with two args → sets custom rate and logs history")
    void constructorTwoArgs_setsBalanceAndRate() {
        // Assert (utilizing setup)
        assertEquals(INITIAL_BALANCE, account.getBalance(), DELTA);
        assertEquals(INTEREST_RATE, account.getInterestRate(), DELTA);
        assertTrue(account.getHistory().get(0).contains(String.valueOf(INITIAL_BALANCE)));
    }

    @Test
    @DisplayName("Constructor with negative balance → throws IllegalArgumentException")
    void constructor_negativeBalance_throwsException() {
        // Arrange, Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> 
            new SavingsAccount(-1.0, 0.02)
        );
        assertEquals("Invalid initial values", exception.getMessage());
    }

    @Test
    @DisplayName("Constructor with negative interest rate → throws IllegalArgumentException")
    void constructor_negativeInterestRate_throwsException() {
        // Arrange, Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> 
            new SavingsAccount(100.0, -0.01)
        );
        assertEquals("Invalid initial values", exception.getMessage());
    }

    @Test
    @DisplayName("Process positive transaction → balance increases")
    void processTransaction_positiveAmount_increasesBalance() {
        // Arrange
        double deposit = 500.0;

        // Act
        account.processTransaction(deposit);

        // Assert
        assertEquals(INITIAL_BALANCE + deposit, account.getBalance(), DELTA);
    }

    @Test
    @DisplayName("Process negative transaction within balance → balance decreases")
    void processTransaction_negativeAmountWithinBalance_decreasesBalance() {
        // Arrange
        double withdrawal = -400.0;

        // Act
        account.processTransaction(withdrawal);

        // Assert
        assertEquals(INITIAL_BALANCE + withdrawal, account.getBalance(), DELTA);
    }

    @Test
    @DisplayName("Process negative transaction equal to balance → balance becomes zero")
    void processTransaction_amountEqualsBalance_balanceBecomesZero() {
        // Arrange
        double withdrawal = -INITIAL_BALANCE;

        // Act
        assertDoesNotThrow(() -> account.processTransaction(withdrawal));

        // Assert
        assertEquals(0.0, account.getBalance(), DELTA);
    }

    @Test
    @DisplayName("Process negative transaction exceeding balance → throws InsolventException")
    void processTransaction_amountExceedsBalance_throwsInsolventException() {
        // Arrange
        double withdrawal = -(INITIAL_BALANCE + 0.01);

        // Act & Assert
        InsolventException exception = assertThrows(InsolventException.class, () -> 
            account.processTransaction(withdrawal)
        );
        assertTrue(exception.getMessage().contains("Insufficient balance"));
    }

    @Test
    @DisplayName("Apply interest → balance increases and entry added to history")
    void applyInterest_updatesBalanceAndHistory() {
        // Arrange
        double expectedInterest = INITIAL_BALANCE * INTEREST_RATE;
        double expectedBalance = INITIAL_BALANCE + expectedInterest;

        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalance, account.getBalance(), DELTA);
        List<String> history = account.getHistory();
        assertEquals(2, history.size());
        assertTrue(history.get(1).contains("Interest applied"));
        // Check formatting in history (%.2f)
        String expectedHistoryEntry = String.format("Interest applied: %.2f", expectedInterest);
        assertEquals(expectedHistoryEntry, history.get(1));
    }

    @Test
    @DisplayName("Apply interest with zero balance → balance remains zero")
    void applyInterest_zeroBalance_noBalanceChange() {
        // Arrange
        SavingsAccount emptyAccount = new SavingsAccount(0.0, 0.10);

        // Act
        emptyAccount.applyInterest();

        // Assert
        assertEquals(0.0, emptyAccount.getBalance(), DELTA);
        assertEquals(2, emptyAccount.getHistory().size());
    }

    @Test
    @DisplayName("Get account summary → returns correctly formatted string")
    void getAccountSummary_returnsFormattedString() {
        // Arrange
        account.processTransaction(200.0); // 1. Initial 2. Deposit
        account.applyInterest(); // 3. Interest

        // Act
        String summary = account.getAccountSummary();

        // Assert
        // Balance: 1000 + 200 = 1200. Interest: 1200 * 0.05 = 60. Total: 1260
        String expectedSummary = String.format("Balance: %.2f | Transactions: %d", 1260.0, 3);
        assertEquals(expectedSummary, summary);
    }

    @Test
    @DisplayName("Get history → returns an immutable copy of the list")
    void getHistory_returnsImmutableCopy() {
        // Arrange
        List<String> history = account.getHistory();
        int originalSize = history.size();

        // Act & Assert
        assertThrows(UnsupportedOperationException.class, () -> {
            history.add("External modification attempt");
        }, "History list should be immutable or a copy that doesn't affect internal state via List.copyOf");

        assertEquals(originalSize, account.getHistory().size());
    }

    @Test
    @DisplayName("ToString → returns expected string representation")
    void toString_returnsCorrectFormat() {
        // Arrange
        String expected = "SavingsAccount{balance=" + INITIAL_BALANCE + ", interestRate=" + INTEREST_RATE + "}";

        // Act
        String actual = account.toString();

        // Assert
        assertEquals(expected, actual);
    }

    @ParameterizedTest
    @ValueSource(doubles = {0.0, 1.0, 1000000.0})
    @DisplayName("Valid initial balances → initialize correctly")
    void constructor_validBalances(double balance) {
        SavingsAccount sa = new SavingsAccount(balance);
        assertEquals(balance, sa.getBalance());
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

@DisplayName("SavingsAccount Unit Tests")
class SavingsAccountTest {

    private SavingsAccount account;
    private static final double INITIAL_BALANCE = 1000.0;
    private static final double INTEREST_RATE = 0.05;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(INITIAL_BALANCE, INTEREST_RATE);
    }

    @Test
    @DisplayName("Constructor (Single Arg) -> Sets default interest rate and initial balance")
    void constructorSingleArg_SetsDefaultValues() {
        // Arrange & Act
        SavingsAccount defaultAccount = new SavingsAccount(500.0);

        // Assert
        assertEquals(500.0, defaultAccount.getBalance(), "Balance should match initial input");
        assertEquals(0.02, defaultAccount.getInterestRate(), "Interest rate should be default 0.02");
        assertEquals(1, defaultAccount.getHistory().size(), "History should contain opening record");
    }

    @Test
    @DisplayName("Constructor (Dual Arg) -> Throws IllegalArgumentException for negative balance")
    void constructor_NegativeBalance_ThrowsException() {
        // Act & Assert
        assertThrows(IllegalArgumentException.class, () -> new SavingsAccount(-1.0, 0.02),
                "Negative initial balance should throw IllegalArgumentException");
    }

    @Test
    @DisplayName("Constructor (Dual Arg) -> Throws IllegalArgumentException for negative interest rate")
    void constructor_NegativeInterest_ThrowsException() {
        // Act & Assert
        assertThrows(IllegalArgumentException.class, () -> new SavingsAccount(100.0, -0.01),
                "Negative interest rate should throw IllegalArgumentException");
    }

    @ParameterizedTest
    @ValueSource(doubles = {0.0, 500.0, 10000.0})
    @DisplayName("processTransaction (Deposit) -> Positive or zero amount increases balance")
    void processTransaction_Deposit_IncreasesBalance(double amount) {
        // Arrange
        double expectedBalance = INITIAL_BALANCE + amount;

        // Act
        account.processTransaction(amount);

        // Assert
        assertEquals(expectedBalance, account.getBalance(), "Balance should increase by deposit amount");
    }

    @Test
    @DisplayName("processTransaction (Withdrawal) -> Valid amount decreases balance")
    void processTransaction_Withdrawal_DecreasesBalance() {
        // Arrange
        double withdrawalAmount = -400.0;
        double expectedBalance = 600.0;

        // Act
        account.processTransaction(withdrawalAmount);

        // Assert
        assertEquals(expectedBalance, account.getBalance(), "Balance should decrease by absolute withdrawal amount");
    }

    @Test
    @DisplayName("processTransaction (Withdrawal) -> Boundary value (exact balance) results in zero balance")
    void processTransaction_WithdrawalExactBalance_ResultsInZero() {
        // Arrange
        double withdrawalAmount = -INITIAL_BALANCE;

        // Act
        account.processTransaction(withdrawalAmount);

        // Assert
        assertEquals(0.0, account.getBalance(), "Balance should be exactly zero");
    }

    @Test
    @DisplayName("processTransaction (Withdrawal) -> Amount exceeding balance throws InsolventException")
    void processTransaction_ExceedingBalance_ThrowsInsolventException() {
        // Arrange
        double withdrawalAmount = -1001.0;

        // Act & Assert
        InsolventException exception = assertThrows(InsolventException.class, () -> 
                account.processTransaction(withdrawalAmount));

        assertTrue(exception.getMessage().contains("-1001.0"), "Exception message should contain the invalid amount");
        assertEquals(INITIAL_BALANCE, account.getBalance(), "Balance should remain unchanged after failed transaction");
    }

    @Test
    @DisplayName("applyInterest -> Correctly calculates interest and updates history")
    void applyInterest_CalculatesCorrectly() {
        // Arrange
        double expectedInterest = INITIAL_BALANCE * INTEREST_RATE; // 1000 * 0.05 = 50
        double expectedBalance = INITIAL_BALANCE + expectedInterest;

        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalance, account.getBalance(), "Balance should include added interest");
        List<String> history = account.getHistory();
        assertEquals(2, history.size(), "History should contain opening and interest entries");
        assertTrue(history.get(1).contains("Interest applied: 50.00"), "History should log correct interest amount");
    }

    @Test
    @DisplayName("getAccountSummary -> Returns correctly formatted string")
    void getAccountSummary_ReturnsFormattedString() {
        // Arrange
        account.processTransaction(200.0); // History size = 2, Balance = 1200
        String expectedSummary = "Balance: 1200.00 | Transactions: 2";

        // Act
        String actualSummary = account.getAccountSummary();

        // Assert
        assertEquals(expectedSummary, actualSummary, "Summary format mismatch");
    }

    @Test
    @DisplayName("getHistory -> Returns immutable copy of the history list")
    void getHistory_ReturnsImmutableCopy() {
        // Arrange
        List<String> history = account.getHistory();

        // Act & Assert
        assertThrows(UnsupportedOperationException.class, () -> history.add("Illegal Entry"),
                "Returned history list should be immutable");
    }

    @Test
    @DisplayName("toString -> Returns expected state representation")
    void toString_ReturnsCorrectFormat() {
        // Arrange
        String expected = "SavingsAccount{balance=1000.0, interestRate=0.05}";

        // Act
        String actual = account.toString();

        // Assert
        assertEquals(expected, actual, "toString output mismatch");
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Unit tests for SavingsAccount focusing on logic, state transitions, and edge cases.
 * Aims for 100% line and branch coverage.
 */
class SavingsAccountTest {

    private static final double DELTA = 0.0001;
    private static final double DEFAULT_RATE = 0.02;

    private SavingsAccount account;

    @BeforeEach
    void setUp() {
        // Arrange
        account = new SavingsAccount(1000.0, 0.05);
    }

    @Test
    @DisplayName("Constructor (Single Arg) → initializes with default interest rate")
    void constructor_SingleArg_UsesDefaultInterestRate() {
        // Act
        SavingsAccount defaultAccount = new SavingsAccount(500.0);

        // Assert
        assertEquals(500.0, defaultAccount.getBalance(), DELTA);
        assertEquals(DEFAULT_RATE, defaultAccount.getInterestRate(), DELTA);
        assertEquals(1, defaultAccount.getHistory().size());
        assertTrue(defaultAccount.getHistory().get(0).contains("Account opened with: 500.0"));
    }

    @Test
    @DisplayName("Constructor (Two Args) → initializes balance and rate correctly")
    void constructor_TwoArgs_InitializesCorrectly() {
        // Assert
        assertEquals(1000.0, account.getBalance(), DELTA);
        assertEquals(0.05, account.getInterestRate(), DELTA);
    }

    @Test
    @DisplayName("Constructor → throws IllegalArgumentException for negative balance")
    void constructor_NegativeBalance_ThrowsException() {
        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, 
            () -> new SavingsAccount(-1.0, 0.05));
        assertEquals("Invalid initial values", exception.getMessage());
    }

    @Test
    @DisplayName("Constructor → throws IllegalArgumentException for negative interest rate")
    void constructor_NegativeRate_ThrowsException() {
        // Act & Assert
        assertThrows(IllegalArgumentException.class, () -> new SavingsAccount(100.0, -0.01));
    }

    @Test
    @DisplayName("applyInterest → adds calculated interest to balance and updates history")
    void applyInterest_StandardValues_UpdatesBalanceAndHistory() {
        // Arrange
        double initialBalance = account.getBalance(); // 1000.0
        double rate = account.getInterestRate(); // 0.05
        double expectedInterest = initialBalance * rate; // 50.0

        // Act
        account.applyInterest();

        // Assert
        assertEquals(1050.0, account.getBalance(), DELTA);
        List<String> history = account.getHistory();
        assertEquals(2, history.size());
        assertEquals("Interest applied: 50.00", history.get(1));
    }

    @Test
    @DisplayName("applyInterest → works correctly when balance is zero")
    void applyInterest_ZeroBalance_NoChangeInBalance() {
        // Arrange
        SavingsAccount zeroAccount = new SavingsAccount(0.0, 0.10);

        // Act
        zeroAccount.applyInterest();

        // Assert
        assertEquals(0.0, zeroAccount.getBalance(), DELTA);
        assertEquals("Interest applied: 0.00", zeroAccount.getHistory().get(1));
    }

    @Test
    @DisplayName("applyInterest → works correctly when interest rate is zero")
    void applyInterest_ZeroInterestRate_NoChangeInBalance() {
        // Arrange
        SavingsAccount noInterestAccount = new SavingsAccount(500.0, 0.0);

        // Act
        noInterestAccount.applyInterest();

        // Assert
        assertEquals(500.0, noInterestAccount.getBalance(), DELTA);
        assertEquals("Interest applied: 0.00", noInterestAccount.getHistory().get(1));
    }

    @Test
    @DisplayName("processTransaction → increases balance for positive amounts")
    void processTransaction_Deposit_IncreasesBalance() {
        // Act
        account.processTransaction(500.0);

        // Assert
        assertEquals(1500.0, account.getBalance(), DELTA);
    }

    @Test
    @DisplayName("processTransaction → decreases balance for valid negative amounts")
    void processTransaction_ValidWithdrawal_DecreasesBalance() {
        // Act
        account.processTransaction(-400.0);

        // Assert
        assertEquals(600.0, account.getBalance(), DELTA);
    }

    @Test
    @DisplayName("processTransaction → throws InsolventException if withdrawal exceeds balance")
    void processTransaction_ExcessiveWithdrawal_ThrowsInsolventException() {
        // Act & Assert
        InsolventException exception = assertThrows(InsolventException.class, 
            () -> account.processTransaction(-1000.01));
        assertTrue(exception.getMessage().contains("Insufficient balance"));
    }

    @Test
    @DisplayName("getAccountSummary → returns correctly formatted string")
    void getAccountSummary_ReturnsCorrectFormat() {
        // Act
        String summary = account.getAccountSummary();

        // Assert
        assertEquals("Balance: 1000.00 | Transactions: 1", summary);
    }

    @Test
    @DisplayName("getHistory → returns an unmodifiable list copy")
    void getHistory_ReturnsUnmodifiableList() {
        // Arrange
        List<String> history = account.getHistory();

        // Act & Assert
        assertThrows(UnsupportedOperationException.class, () -> history.add("Unauthorized entry"));
        assertEquals(1, account.getHistory().size(), "Original history should remain unchanged");
    }

    @Test
    @DisplayName("toString → returns correctly formatted internal state")
    void toString_ReturnsCorrectFormat() {
        // Act
        String result = account.toString();

        // Assert
        assertEquals("SavingsAccount{balance=1000.0, interestRate=0.05}", result);
    }

    @Test
    @DisplayName("Edge Case: Large Balance Interest Calculation")
    void applyInterest_LargeBalance_CalculatesCorrectly() {
        // Arrange
        SavingsAccount largeAccount = new SavingsAccount(1_000_000.0, 0.01);

        // Act
        largeAccount.applyInterest();

        // Assert
        assertEquals(1_010_000.0, largeAccount.getBalance(), DELTA);
        assertEquals("Interest applied: 10000.00", largeAccount.getHistory().get(1));
    }

    @ParameterizedTest
    @ValueSource(doubles = {0.0, 100.0, 999.99, 1000.0})
    @DisplayName("processTransaction → accepts withdrawal exactly equal to or less than balance")
    void processTransaction_BoundaryWithdrawals_DoesNotThrow(double withdrawAmount) {
        // Act & Assert
        assertDoesNotThrow(() -> account.processTransaction(-withdrawAmount));
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

@DisplayName("SavingsAccount Unit Tests")
class SavingsAccountTest {

    private static final double DELTA = 0.0001;
    private static final double INITIAL_BALANCE = 1000.0;
    private static final double INTEREST_RATE = 0.05;

    @Nested
    @DisplayName("Constructor Tests")
    class ConstructorTests {

        @Test
        @DisplayName("Valid initial balance (single arg) → initializes with default rate and history")
        void constructor_ValidInitialBalance_SetsDefaultRate() {
            // Arrange & Act
            SavingsAccount account = new SavingsAccount(500.0);

            // Assert
            assertEquals(500.0, account.getBalance(), DELTA);
            assertEquals(0.02, account.getInterestRate(), DELTA); // Based on DEFAULT_INTEREST_RATE
            assertEquals(1, account.getHistory().size());
            assertTrue(account.getHistory().get(0).contains("Account opened with: 500.0"));
        }

        @Test
        @DisplayName("Valid balance and rate (two args) → initializes correctly")
        void constructor_ValidParams_SetsBalanceAndRate() {
            // Arrange & Act
            SavingsAccount account = new SavingsAccount(INITIAL_BALANCE, INTEREST_RATE);

            // Assert
            assertEquals(INITIAL_BALANCE, account.getBalance(), DELTA);
            assertEquals(INTEREST_RATE, account.getInterestRate(), DELTA);
        }

        @Test
        @DisplayName("Negative initial balance → throws IllegalArgumentException")
        void constructor_NegativeBalance_ThrowsException() {
            // Act & Assert
            IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> 
                new SavingsAccount(-1.0, 0.05)
            );
            assertEquals("Invalid initial values", exception.getMessage());
        }

