package com.bank.logic;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.ByteArrayOutputStream;
import java.io.PrintStream;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.mockito.ArgumentMatchers.anyDouble;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;

public class MainTest {

    private final ByteArrayOutputStream outContent = new ByteArrayOutputStream();
    private final PrintStream originalOut = System.out;
    private SavingsAccount mockAccount;

    @BeforeEach
    void setUp() {
        System.setOut(new PrintStream(outContent));
        mockAccount = Mockito.mock(SavingsAccount.class);
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
    }

    /**
     * Helper method to invoke the private static handleDeposit method using reflection.
     */
    private void invokeHandleDeposit(Scanner scanner, SavingsAccount account) throws Exception {
        Method method = Main.class.getDeclaredMethod("handleDeposit", Scanner.class, SavingsAccount.class);
        method.setAccessible(true);
        try {
            method.invoke(null, scanner, account);
        } catch (InvocationTargetException e) {
            if (e.getCause() instanceof Exception) {
                throw (Exception) e.getCause();
            }
            throw e;
        }
    }

    @Test
    @DisplayName("Valid positive amount → deposit succeeds and state updates")
    void testHandleDeposit_ValidAmount_Success() throws Exception {
        // Arrange
        String input = "500.0\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleDeposit(scanner, mockAccount);

        // Assert
        verify(mockAccount).processTransaction(500.0);
        assertTrue(outContent.toString().contains("Deposit successful."));
    }

    @Test
    @DisplayName("Amount is zero → prints error and does not process transaction")
    void testHandleDeposit_ZeroAmount_ShowsError() throws Exception {
        // Arrange
        String input = "0.0\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleDeposit(scanner, mockAccount);

        // Assert
        verify(mockAccount, never()).processTransaction(anyDouble());
        assertTrue(outContent.toString().contains("Amount must be positive."));
    }

    @Test
    @DisplayName("Amount is negative → prints error and does not process transaction")
    void testHandleDeposit_NegativeAmount_ShowsError() throws Exception {
        // Arrange
        String input = "-100.50\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleDeposit(scanner, mockAccount);

        // Assert
        verify(mockAccount, never()).processTransaction(anyDouble());
        assertTrue(outContent.toString().contains("Amount must be positive."));
    }

    @Test
    @DisplayName("Input is non-numeric followed by valid amount → loops and then succeeds")
    void testHandleDeposit_InvalidInputThenValid_LoopsAndSucceeds() throws Exception {
        // Arrange
        // First input is text, second is valid double
        String input = "invalid_text\n250.0\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleDeposit(scanner, mockAccount);

        // Assert
        verify(mockAccount).processTransaction(250.0);
        String output = outContent.toString();
        assertTrue(output.contains("Invalid input. Please enter a valid number."));
        assertTrue(output.contains("Deposit successful."));
    }

    @Test
    @DisplayName("Account logic throws InsolventException → exception propagates to caller")
    void testHandleDeposit_InsolventException_Propagates() throws Exception {
        // Arrange
        String input = "100.0\n";
        Scanner scanner = new Scanner(input);
        Mockito.doThrow(new InsolventException("Business logic failure"))
                .when(mockAccount).processTransaction(100.0);

        // Act & Assert
        InsolventException exception = assertThrows(InsolventException.class, () -> {
            invokeHandleDeposit(scanner, mockAccount);
        });
        assertEquals("Business logic failure", exception.getMessage());
    }

    @Test
    @DisplayName("Extremely large deposit amount → processes successfully")
    void testHandleDeposit_LargeAmount_Success() throws Exception {
        // Arrange
        double largeAmount = 1_000_000_000.0;
        String input = largeAmount + "\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleDeposit(scanner, mockAccount);

        // Assert
        verify(mockAccount).processTransaction(largeAmount);
        assertTrue(outContent.toString().contains("Deposit successful."));
    }
}

