package com.bank.logic;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import java.io.ByteArrayOutputStream;
import java.io.PrintStream;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

/**
 * Test class for Main.readDouble focusing on branch coverage, 
 * input validation, and loop handling.
 */
class MainTest {

    private final ByteArrayOutputStream outContent = new ByteArrayOutputStream();
    private final PrintStream originalOut = System.out;
    private Method readDoubleMethod;

    @BeforeEach
    void setUp() throws NoSuchMethodException {
        System.setOut(new PrintStream(outContent));
        // Accessing private static method readDouble(Scanner, String)
        readDoubleMethod = Main.class.getDeclaredMethod("readDouble", Scanner.class, String.class);
        readDoubleMethod.setAccessible(true);
    }

    @AfterEach
    void restoreStreams() {
        System.setOut(originalOut);
    }

    private double invokeReadDouble(Scanner scanner, String message) throws Throwable {
        try {
            return (double) readDoubleMethod.invoke(null, scanner, message);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }

    @Test
    @DisplayName("Valid positive double input → returns correct double value")
    void readDouble_ValidPositiveInput_ReturnsValue() throws Throwable {
        // Arrange
        String input = "150.75\n";
        Scanner scanner = new Scanner(input);
        String prompt = "Enter amount: ";

        // Act
        double result = invokeReadDouble(scanner, prompt);

        // Assert
        assertEquals(150.75, result, 0.001);
        assertTrue(outContent.toString().contains(prompt));
    }

    @Test
    @DisplayName("Valid zero input → returns 0.0")
    void readDouble_ZeroInput_ReturnsZero() throws Throwable {
        // Arrange
        String input = "0.0\n";
        Scanner scanner = new Scanner(input);

        // Act
        double result = invokeReadDouble(scanner, "Prompt: ");

        // Assert
        assertEquals(0.0, result, 0.001);
    }

    @Test
    @DisplayName("Valid negative double input → returns negative value")
    void readDouble_NegativeInput_ReturnsNegativeValue() throws Throwable {
        // Arrange
        String input = "-50.25\n";
        Scanner scanner = new Scanner(input);

        // Act
        double result = invokeReadDouble(scanner, "Prompt: ");

        // Assert
        assertEquals(-50.25, result, 0.001);
    }

    @ParameterizedTest
    @ValueSource(strings = {"9999999.99", "0.000001"})
    @DisplayName("Boundary double values → returns exact values")
    void readDouble_BoundaryValues_ReturnsExactValues(String val) throws Throwable {
        // Arrange
        Scanner scanner = new Scanner(val + "\n");
        double expected = Double.parseDouble(val);

        // Act
        double result = invokeReadDouble(scanner, "Prompt: ");

        // Assert
        assertEquals(expected, result, 0.0000001);
    }

    @Test
    @DisplayName("Non-numeric input followed by valid double → clears buffer and eventually returns double")
    void readDouble_InvalidThenValidInput_RetriesAndReturnsDouble() throws Throwable {
        // Arrange
        // "abc" is invalid, "100.50" is valid
        String input = "abc\n100.50\n";
        Scanner scanner = new Scanner(input);
        String prompt = "Enter amount: ";

        // Act
        double result = invokeReadDouble(scanner, prompt);

        // Assert
        assertEquals(100.50, result, 0.001);
        String output = outContent.toString();
        assertTrue(output.contains("Invalid input. Please enter a valid number."));
        // Check that prompt was printed twice (once for initial, once after error)
        int promptCount = output.split(prompt).length - 1;
        assertEquals(2, promptCount);
    }

    @Test
    @DisplayName("Multiple invalid inputs → continues looping until valid double is provided")
    void readDouble_MultipleInvalidInputs_LoopsUntilValid() throws Throwable {
        // Arrange
        String input = "not_a_number\n!!!\n42.42\n";
        Scanner scanner = new Scanner(input);

        // Act
        double result = invokeReadDouble(scanner, "Prompt: ");

        // Assert
        assertEquals(42.42, result, 0.001);
        String output = outContent.toString();
        // Check for multiple error messages
        int errorCount = (output.split("Invalid input. Please enter a valid number.").length) - 1;
        assertEquals(2, errorCount);
    }

    @Test
    @DisplayName("Space-separated numeric input → returns first valid double")
    void readDouble_SpaceSeparatedInput_ReturnsFirstDouble() throws Throwable {
        // Arrange
        String input = " 10.1  20.2 \n";
        Scanner scanner = new Scanner(input);

        // Act
        double result = invokeReadDouble(scanner, "Prompt: ");

        // Assert
        assertEquals(10.1, result, 0.001);
    }

    @Test
    @DisplayName("Large double input (Scientific Notation) → correctly parses")
    void readDouble_ScientificNotation_ReturnsValue() throws Throwable {
        // Arrange
        String input = "1.5e3\n"; // 1500.0
        Scanner scanner = new Scanner(input);

        // Act
        double result = invokeReadDouble(scanner, "Prompt: ");

        // Assert
        assertEquals(1500.0, result, 0.001);
    }
}

package com.bank.logic;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

/**
 * Unit tests for InsolventException focusing on constructor behavior and inheritance.
 * Aiming for 100% line and branch coverage.
 */
class InsolventExceptionTest {

    @Test
    @DisplayName("Constructor with valid message → returns message via getMessage()")
    void constructor_WithValidMessage_ShouldStoreMessage() {
        // Arrange
        String expectedMessage = "Insufficient funds for withdrawal";

        // Act
        InsolventException exception = new InsolventException(expectedMessage);

        // Assert
        assertEquals(expectedMessage, exception.getMessage(), "The exception message should match the input provided to the constructor.");
    }

    @Test
    @DisplayName("Constructor with null message → getMessage() returns null")
    void constructor_WithNullMessage_ShouldReturnNullMessage() {
        // Arrange
        String expectedMessage = null;

        // Act
        InsolventException exception = new InsolventException(expectedMessage);

        // Assert
        assertNull(exception.getMessage(), "The exception message should be null if null was provided.");
    }

    @Test
    @DisplayName("Constructor with empty string → getMessage() returns empty string")
    void constructor_WithEmptyMessage_ShouldReturnEmptyString() {
        // Arrange
        String expectedMessage = "";

        // Act
        InsolventException exception = new InsolventException(expectedMessage);

        // Assert
        assertEquals("", exception.getMessage(), "The exception message should be an empty string if an empty string was provided.");
    }

    @Test
    @DisplayName("Throw InsolventException → can be caught as RuntimeException")
    void exception_WhenThrown_ShouldBeCatchableAsRuntimeException() {
        // Arrange
        String message = "Insolvency detected";

        // Act & Assert
        RuntimeException exception = assertThrows(RuntimeException.class, () -> {
            throw new InsolventException(message);
        }, "InsolventException should be catchable as a RuntimeException.");

        assertTrue(exception instanceof InsolventException, "The thrown exception should be an instance of InsolventException.");
        assertEquals(message, exception.getMessage());
    }

    @Test
    @DisplayName("Constructor with very large string → stores message correctly")
    void constructor_WithLargeString_ShouldStoreEntireMessage() {
        // Arrange
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 1000; i++) {
            sb.append("A");
        }
        String largeMessage = sb.toString();

        // Act
        InsolventException exception = new InsolventException(largeMessage);

        // Assert
        assertEquals(largeMessage, exception.getMessage(), "The exception should handle large strings without truncation.");
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;
import org.junit.jupiter.params.provider.ValueSource;

import java.lang.reflect.Field;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class SavingsAccountTest {

    private static final double EPSILON = 0.0001;
    private SavingsAccount account;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(1000.0, 0.05);
    }

    @Test
    @DisplayName("Constructor with only balance uses default interest rate → balance set, default interest rate applied")
    void constructorSingleParameter_usesDefaultInterestRate() {
        // Arrange & Act
        SavingsAccount acc = new SavingsAccount(500.0);

        // Assert
        assertEquals(500.0, acc.getBalance(), EPSILON);
        assertEquals(SavingsAccount.DEFAULT_INTEREST_RATE, acc.getInterestRate(), EPSILON);
        List<String> history = acc.getHistory();
        assertFalse(history.isEmpty());
        assertTrue(history.get(0).contains("Account opened with: 500.0"));
    }

    @Test
    @DisplayName("Constructor with valid parameters → balance and interest rate set, history initialized")
    void constructorTwoParameters_validValues_setsFieldsAndHistory() {
        // Arrange & Act
        SavingsAccount acc = new SavingsAccount(1500.0, 0.03);

        // Assert
        assertEquals(1500.0, acc.getBalance(), EPSILON);
        assertEquals(0.03, acc.getInterestRate(), EPSILON);
        List<String> history = acc.getHistory();
        assertEquals(1, history.size());
        assertTrue(history.get(0).contains("1500.0"));
    }

    @Test
    @DisplayName("Constructor with negative initial balance → throws IllegalArgumentException")
    void constructor_negativeBalance_throwsIllegalArgumentException() {
        // Arrange, Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> new SavingsAccount(-100.0, 0.05));
        assertEquals("Invalid initial values", exception.getMessage());
    }

    @Test
    @DisplayName("Constructor with negative interest rate → throws IllegalArgumentException")
    void constructor_negativeInterestRate_throwsIllegalArgumentException() {
        // Arrange, Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> new SavingsAccount(1000.0, -0.01));
        assertEquals("Invalid initial values", exception.getMessage());
    }

    @Test
    @DisplayName("Constructor with both negative values → throws IllegalArgumentException")
    void constructor_bothNegativeValues_throwsIllegalArgumentException() {
        // Arrange, Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> new SavingsAccount(-100.0, -0.01));
        assertEquals("Invalid initial values", exception.getMessage());
    }

    @Test
    @DisplayName("Constructor with zero balance and zero interest rate → valid account created")
    void constructor_zeroValues_validAccount() {
        // Arrange & Act
        SavingsAccount acc = new SavingsAccount(0.0, 0.0);

        // Assert
        assertEquals(0.0, acc.getBalance(), EPSILON);
        assertEquals(0.0, acc.getInterestRate(), EPSILON);
        assertEquals(1, acc.getHistory().size());
    }

    @ParameterizedTest
    @DisplayName("ProcessTransaction with positive amount → balance increases by amount")
    @ValueSource(doubles = {50.0, 100.5, 0.01, 1000000.0})
    void processTransaction_positiveAmount_increasesBalance(double amount) {
        // Arrange
        double initialBalance = account.getBalance();

        // Act
        account.processTransaction(amount);

        // Assert
        assertEquals(initialBalance + amount, account.getBalance(), EPSILON);
    }

    @ParameterizedTest
    @DisplayName("ProcessTransaction with negative amount within balance → balance decreases by amount")
    @ValueSource(doubles = {-50.0, -100.5, -0.01, -999.99})
    void processTransaction_negativeAmountWithinBalance_decreasesBalance(double amount) {
        // Arrange
        double initialBalance = account.getBalance();

        // Act
        account.processTransaction(amount);

        // Assert
        assertEquals(initialBalance + amount, account.getBalance(), EPSILON);
    }

    @Test
    @DisplayName("ProcessTransaction with negative amount equal to balance → balance becomes zero")
    void processTransaction_negativeAmountEqualToBalance_balanceBecomesZero() {
        // Arrange
        double amount = -account.getBalance();

        // Act
        account.processTransaction(amount);

        // Assert
        assertEquals(0.0, account.getBalance(), EPSILON);
    }

    @Test
    @DisplayName("ProcessTransaction with negative amount exceeding balance → throws InsolventException")
    void processTransaction_negativeAmountExceedingBalance_throwsInsolventException() {
        // Arrange
        double amount = -(account.getBalance() + 0.01);

        // Act & Assert
        InsolventException exception = assertThrows(InsolventException.class,
                () -> account.processTransaction(amount));
        assertTrue(exception.getMessage().contains("Insufficient balance"));
        assertEquals(1000.0, account.getBalance(), EPSILON); // Balance unchanged
    }

    @Test
    @DisplayName("ProcessTransaction with zero amount → balance unchanged")
    void processTransaction_zeroAmount_balanceUnchanged() {
        // Arrange
        double initialBalance = account.getBalance();

        // Act
        account.processTransaction(0.0);

        // Assert
        assertEquals(initialBalance, account.getBalance(), EPSILON);
    }

    @Test
    @DisplayName("ApplyInterest with positive balance → balance increases by interest, history updated")
    void applyInterest_positiveBalance_appliesInterestAndUpdatesHistory() throws Exception {
        // Arrange
        double initialBalance = account.getBalance();
        double interestRate = account.getInterestRate();
        double expectedInterest = initialBalance * interestRate;

        // Access private history field for verification
        Field historyField = SavingsAccount.class.getDeclaredField("history");
        historyField.setAccessible(true);
        List<String> history = (List<String>) historyField.get(account);
        int initialHistorySize = history.size();

        // Act
        account.applyInterest();

        // Assert
        assertEquals(initialBalance + expectedInterest, account.getBalance(), EPSILON);
        assertEquals(initialHistorySize + 1, history.size());
        String lastEntry = history.get(history.size() - 1);
        assertTrue(lastEntry.contains(String.format("Interest applied: %.2f", expectedInterest)));
    }

    @Test
    @DisplayName("ApplyInterest with zero balance → balance remains zero, history updated")
    void applyInterest_zeroBalance_noChangeButHistoryUpdated() throws Exception {
        // Arrange
        SavingsAccount zeroAccount = new SavingsAccount(0.0, 0.05);
        Field historyField = SavingsAccount.class.getDeclaredField("history");
        historyField.setAccessible(true);
        List<String> history = (List<String>) historyField.get(zeroAccount);
        int initialHistorySize = history.size();

        // Act
        zeroAccount.applyInterest();

        // Assert
        assertEquals(0.0, zeroAccount.getBalance(), EPSILON);
        assertEquals(initialHistorySize + 1, history.size());
        assertTrue(history.get(history.size() - 1).contains("Interest applied: 0.00"));
    }

    @Test
    @DisplayName("ApplyInterest with zero interest rate → balance unchanged, history updated")
    void applyInterest_zeroInterestRate_balanceUnchanged() throws Exception {
        // Arrange
        SavingsAccount zeroInterestAccount = new SavingsAccount(1000.0, 0.0);
        double initialBalance = zeroInterestAccount.getBalance();
        Field historyField = SavingsAccount.class.getDeclaredField("history");
        historyField.setAccessible(true);
        List<String> history = (List<String>) historyField.get(zeroInterestAccount);
        int initialHistorySize = history.size();

        // Act
        zeroInterestAccount.applyInterest();

        // Assert
        assertEquals(initialBalance, zeroInterestAccount.getBalance(), EPSILON);
        assertEquals(initialHistorySize + 1, history.size());
        assertTrue(history.get(history.size() - 1).contains("Interest applied: 0.00"));
    }

    @Test
    @DisplayName("GetAccountSummary → returns formatted string with balance and transaction count")
    void getAccountSummary_returnsCorrectFormat() {
        // Arrange
        account.processTransaction(200.0);
        account.processTransaction(-100.0);

        // Act
        String summary = account.getAccountSummary();

        // Assert
        assertTrue(summary.contains(String.format("Balance: %.2f", account.getBalance())));
        assertTrue(summary.contains("Transactions: 3")); // Initial + 2 transactions
    }

    @Test
    @DisplayName("GetAccountSummary with no transactions → shows initial transaction only")
    void getAccountSummary_newAccount_showsOneTransaction() {
        // Act
        String summary = account.getAccountSummary();

        // Assert
        assertTrue(summary.contains("Transactions: 1"));
    }

    @Test
    @DisplayName("GetBalance → returns current balance")
    void getBalance_returnsCurrentBalance() {
        // Arrange
        double expected = 1000.0;

        // Act & Assert
        assertEquals(expected, account.getBalance(), EPSILON);
    }

    @Test
    @DisplayName("GetInterestRate → returns current interest rate")
    void getInterestRate_returnsCurrentInterestRate() {
        // Arrange
        double expected = 0.05;

        // Act & Assert
        assertEquals(expected, account.getInterestRate(), EPSILON);
    }

    @Test
    @DisplayName("GetHistory → returns unmodifiable copy of history")
    void getHistory_returnsUnmodifiableCopy() {
        // Arrange
        List<String> history = account.getHistory();

        // Act & Assert
        assertEquals(1, history.size());
        assertThrows(UnsupportedOperationException.class, () -> history.add("Illegal entry"));
    }

    @Test
    @DisplayName("GetHistory after multiple operations → returns all history entries")
    void getHistory_multipleOperations_returnsAllEntries() throws Exception {
        // Arrange
        account.processTransaction(500.0);
        account.applyInterest();

        // Act
        List<String> history = account.getHistory();

        // Assert
        assertEquals(3, history.size());
        assertTrue(history.get(0).contains("Account opened with:"));
        assertTrue(history.get(2).contains("Interest applied:"));
    }

    @Test
    @DisplayName("ToString → returns string representation with balance and interest rate")
    void toString_returnsCorrectFormat() {
        // Act
        String result = account.toString();

        // Assert
        assertTrue(result.contains("balance=1000.0"));
        assertTrue(result.contains("interestRate=0.05"));
        assertTrue(result.contains("SavingsAccount{"));
    }

    @ParameterizedTest
    @DisplayName("ProcessTransaction boundary cases → handles edge values correctly")
    @CsvSource({
            "0.0, 1000.0",
            "0.01, 1000.01",
            "-0.01, 999.99",
            "Double.MAX_VALUE, Infinity",
            "-1000.0, 0.0"
    })
    void processTransaction_boundaryValues_handlesCorrectly(double amount, double expectedBalance) {
        // Arrange
        if (amount == Double.MAX_VALUE) {
            // Special case: overflow
            account.processTransaction(amount);
            assertTrue(Double.isInfinite(account.getBalance()));
        } else if (amount == -1000.0) {
            // Exact balance withdrawal
            account.processTransaction(amount);
            assertEquals(expectedBalance, account.getBalance(), EPSILON);
        } else {
            // Normal cases
            account.processTransaction(amount);
            assertEquals(expectedBalance, account.getBalance(), EPSILON);
        }
    }

    @Test
    @DisplayName("Default interest rate constant → has correct value")
    void defaultInterestRate_constantHasCorrectValue() throws Exception {
        // Arrange
        Field defaultRateField = SavingsAccount.class.getDeclaredField("DEFAULT_INTEREST_RATE");
        defaultRateField.setAccessible(true);

        // Act
        double defaultRate = (double) defaultRateField.get(null);

        // Assert
        assertEquals(0.02, defaultRate, EPSILON);
    }

    @Test
    @DisplayName("ApplyInterest synchronized → can be called multiple times without race conditions")
    void applyInterest_synchronized_multipleCallsWork() {
        // Arrange
        double initialBalance = account.getBalance();
        double interestRate = account.getInterestRate();
        double expectedAfterOne = initialBalance * (1 + interestRate);
        double expectedAfterTwo = expectedAfterOne * (1 + interestRate);

        // Act
        account.applyInterest();
        assertEquals(expectedAfterOne, account.getBalance(), EPSILON);

        account.applyInterest();
        assertEquals(expectedAfterTwo, account.getBalance(), EPSILON);
    }

    @Test
    @DisplayName("ProcessTransaction with large negative amount just below balance → throws InsolventException")
    void processTransaction_largeNegativeAmountJustBelowBalance_throwsException() {
        // Arrange
        double amount = -(account.getBalance() + 0.000001);

        // Act & Assert
        assertThrows(InsolventException.class, () -> account.processTransaction(amount));
    }
}

