package com.bank.logic;

import org.junit.jupiter.api.*;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;
import java.util.List;
import static org.junit.jupiter.api.Assertions.*;

class SavingsAccountProcessTransactionTest {

    private SavingsAccount account;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(1000.0, 0.03);
    }

    @Test
    @DisplayName("Deposit positive amount → balance increases correctly")
    void processTransaction_PositiveAmount_DepositsSuccessfully() {
        // Arrange
        double initialBalance = account.getBalance();
        double depositAmount = 500.0;
        double expectedBalance = initialBalance + depositAmount;

        // Act
        assertDoesNotThrow(() -> account.processTransaction(depositAmount));

        // Assert
        assertEquals(expectedBalance, account.getBalance(), 0.001,
                "Balance should increase by deposit amount");
    }

    @Test
    @DisplayName("Deposit zero amount → balance remains unchanged")
    void processTransaction_ZeroAmount_BalanceUnchanged() {
        // Arrange
        double initialBalance = account.getBalance();

        // Act
        assertDoesNotThrow(() -> account.processTransaction(0.0));

        // Assert
        assertEquals(initialBalance, account.getBalance(), 0.001,
                "Balance should remain unchanged after zero deposit");
    }

    @Test
    @DisplayName("Withdraw negative amount within balance → balance decreases correctly")
    void processTransaction_NegativeAmountWithinBalance_WithdrawsSuccessfully() {
        // Arrange
        double initialBalance = account.getBalance();
        double withdrawalAmount = -300.0;
        double expectedBalance = initialBalance + withdrawalAmount;

        // Act
        assertDoesNotThrow(() -> account.processTransaction(withdrawalAmount));

        // Assert
        assertEquals(expectedBalance, account.getBalance(), 0.001,
                "Balance should decrease by withdrawal amount");
    }

    @Test
    @DisplayName("Withdraw amount equal to balance → balance becomes zero")
    void processTransaction_NegativeAmountEqualToBalance_BalanceBecomesZero() {
        // Arrange
        double initialBalance = account.getBalance();
        double withdrawalAmount = -initialBalance;
        double expectedBalance = 0.0;

        // Act
        assertDoesNotThrow(() -> account.processTransaction(withdrawalAmount));

        // Assert
        assertEquals(expectedBalance, account.getBalance(), 0.001,
                "Balance should be zero after withdrawing entire balance");
    }

    @Test
    @DisplayName("Withdraw exceeding balance → throws InsolventException")
    void processTransaction_NegativeAmountExceedingBalance_ThrowsException() {
        // Arrange
        double initialBalance = account.getBalance();
        double withdrawalAmount = -(initialBalance + 100.0);
        String expectedMessage = "Insufficient balance: " + withdrawalAmount;

        // Act & Assert
        InsolventException exception = assertThrows(
                InsolventException.class,
                () -> account.processTransaction(withdrawalAmount),
                "Should throw InsolventException when withdrawal exceeds balance"
        );

        assertEquals(expectedMessage, exception.getMessage(),
                "Exception message should indicate insufficient balance");

        assertEquals(initialBalance, account.getBalance(), 0.001,
                "Balance should remain unchanged after failed withdrawal");
    }

    @ParameterizedTest
    @ValueSource(doubles = {Double.MAX_VALUE, -Double.MAX_VALUE, 1E308, -1E308})
    @DisplayName("Process transaction with extreme double values → handles without overflow")
    void processTransaction_ExtremeDoubleValues_HandlesWithoutOverflow(double amount) {
        // Arrange
        if (amount < 0 && Math.abs(amount) > account.getBalance()) {
            // Act & Assert
            assertThrows(InsolventException.class,
                    () -> account.processTransaction(amount),
                    "Should throw exception for extreme negative amounts exceeding balance");
        } else {
            // Act
            assertDoesNotThrow(() -> account.processTransaction(amount));

            // Assert - Just verify no crash occurred and balance is updated
            double expectedBalance = 1000.0 + amount;
            if (Double.isFinite(expectedBalance)) {
                assertEquals(expectedBalance, account.getBalance(), 0.001,
                        "Balance should handle extreme values correctly");
            }
        }
    }

    @Test
    @DisplayName("Multiple sequential transactions → cumulative effect correct")
    void processTransaction_MultipleSequentialTransactions_BalanceUpdatesCorrectly() {
        // Arrange
        double[] transactions = {500.0, -200.0, -100.0, 150.0};
        double expectedFinalBalance = 1000.0 + 500.0 - 200.0 - 100.0 + 150.0;

        // Act
        for (double amount : transactions) {
            if (amount < 0 && Math.abs(amount) > account.getBalance()) {
                assertThrows(InsolventException.class,
                        () -> account.processTransaction(amount));
            } else {
                assertDoesNotThrow(() -> account.processTransaction(amount));
            }
        }

        // Assert
        assertEquals(expectedFinalBalance, account.getBalance(), 0.001,
                "Final balance should reflect all successful transactions");
    }

    @Test
    @DisplayName("Transaction history unchanged → processTransaction doesn't modify history")
    void processTransaction_AnyTransaction_HistoryRemainsUnchanged() {
        // Arrange
        List<String> initialHistory = account.getHistory();
        int initialHistorySize = initialHistory.size();

        // Act
        account.processTransaction(500.0);

        // Assert
        List<String> finalHistory = account.getHistory();
        assertEquals(initialHistorySize, finalHistory.size(),
                "History size should not change after transaction");
        assertEquals(initialHistory, finalHistory,
                "History content should remain unchanged after transaction");
    }

    @Test
    @DisplayName("Account summary reflects transaction → getAccountSummary shows updated count")
    void processTransaction_MultipleTransactions_AccountSummaryUnchanged() {
        // Arrange
        String initialSummary = account.getAccountSummary();

        // Act
        account.processTransaction(500.0);

        // Assert - Summary should show same transaction count since history unchanged
        String finalSummary = account.getAccountSummary();
        assertNotEquals(initialSummary, finalSummary,
                "Account summary should change after transaction due to balance change");
        assertTrue(finalSummary.contains(String.format("%.2f", 1500.0)),
                "Summary should reflect updated balance");
    }

    @Test
    @DisplayName("Precise double arithmetic → handles floating point precision")
    void processTransaction_PreciseDecimalValues_HandlesFloatingPoint() {
        // Arrange
        SavingsAccount preciseAccount = new SavingsAccount(0.1 + 0.2, 0.01);
        double initialBalance = preciseAccount.getBalance();

        // Act
        preciseAccount.processTransaction(0.3);
        preciseAccount.processTransaction(-0.6);

        // Assert
        double expectedBalance = 0.0;
        assertEquals(expectedBalance, preciseAccount.getBalance(), 1E-10,
                "Should handle floating point arithmetic correctly");
    }

    @Test
    @DisplayName("Withdraw exactly at boundary → succeeds without exception")
    void processTransaction_WithdrawAtBoundary_Succeeds() {
        // Arrange
        SavingsAccount boundaryAccount = new SavingsAccount(100.0);
        double withdrawalAmount = -100.0;

        // Act
        assertDoesNotThrow(() -> boundaryAccount.processTransaction(withdrawalAmount));

        // Assert
        assertEquals(0.0, boundaryAccount.getBalance(), 0.001,
                "Balance should be zero after withdrawing exact amount");
    }

    @Test
    @DisplayName("ToString reflects transaction → shows updated balance")
    void processTransaction_AnyTransaction_ToStringReflectsChange() {
        // Arrange
        String initialString = account.toString();

        // Act
        account.processTransaction(250.0);

        // Assert
        String finalString = account.toString();
        assertNotEquals(initialString, finalString,
                "toString should show different balance after transaction");
        assertTrue(finalString.contains("1250.0") || finalString.contains("1250,"),
                "toString should contain updated balance");
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class SavingsAccountTest {

    private static final double DELTA = 0.000001;
    private SavingsAccount account;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(1000.0, 0.05);
    }

    @Test
    @DisplayName("Apply interest with positive balance → balance increases by correct interest amount")
    void applyInterest_WithPositiveBalance_BalanceIncreasesCorrectly() {
        // Arrange
        double initialBalance = account.getBalance();
        double interestRate = account.getInterestRate();
        double expectedInterest = initialBalance * interestRate;
        double expectedBalance = initialBalance + expectedInterest;
        int initialHistorySize = account.getHistory().size();

        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalance, account.getBalance(), DELTA, "Balance after interest");
        assertEquals(initialHistorySize + 1, account.getHistory().size(), "History size increased");
        List<String> history = account.getHistory();
        String lastEntry = history.get(history.size() - 1);
        assertTrue(lastEntry.contains("Interest applied:"));
        assertTrue(lastEntry.contains(String.format("%.2f", expectedInterest)));
    }

    @Test
    @DisplayName("Apply interest with zero balance → balance remains zero and history updated")
    void applyInterest_WithZeroBalance_BalanceRemainsZero() {
        // Arrange
        account = new SavingsAccount(0.0, 0.10);
        double initialBalance = account.getBalance();
        int initialHistorySize = account.getHistory().size();

        // Act
        account.applyInterest();

        // Assert
        assertEquals(0.0, account.getBalance(), DELTA, "Balance remains zero");
        assertEquals(initialHistorySize + 1, account.getHistory().size(), "History updated");
        List<String> history = account.getHistory();
        String lastEntry = history.get(history.size() - 1);
        assertTrue(lastEntry.contains("Interest applied: 0.00"));
    }

    @Test
    @DisplayName("Apply interest with zero interest rate → balance unchanged")
    void applyInterest_WithZeroInterestRate_BalanceUnchanged() {
        // Arrange
        account = new SavingsAccount(500.0, 0.0);
        double initialBalance = account.getBalance();
        int initialHistorySize = account.getHistory().size();

        // Act
        account.applyInterest();

        // Assert
        assertEquals(initialBalance, account.getBalance(), DELTA, "Balance unchanged");
        assertEquals(initialHistorySize + 1, account.getHistory().size(), "History updated");
        List<String> history = account.getHistory();
        String lastEntry = history.get(history.size() - 1);
        assertTrue(lastEntry.contains("Interest applied: 0.00"));
    }

    @Test
    @DisplayName("Apply interest with maximum double value → balance increases correctly (no overflow)")
    void applyInterest_WithMaxDoubleValue_BalanceIncreasesWithoutOverflow() {
        // Arrange
        double maxValue = Double.MAX_VALUE;
        double interestRate = 0.01;
        account = new SavingsAccount(maxValue, interestRate);
        double expectedInterest = maxValue * interestRate;
        double expectedBalance = maxValue + expectedInterest;
        int initialHistorySize = account.getHistory().size();

        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalance, account.getBalance(), DELTA, "Balance increased correctly");
        assertEquals(initialHistorySize + 1, account.getHistory().size(), "History updated");
    }

    @Test
    @DisplayName("Apply interest with small positive balance and rate → balance increases correctly")
    void applyInterest_WithSmallestPositiveValues_BalanceIncreasesCorrectly() {
        // Arrange
        double smallestBalance = Double.MIN_VALUE;
        double smallestRate = Double.MIN_VALUE;
        account = new SavingsAccount(smallestBalance, smallestRate);
        double expectedInterest = smallestBalance * smallestRate;
        double expectedBalance = smallestBalance + expectedInterest;
        int initialHistorySize = account.getHistory().size();

        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalance, account.getBalance(), DELTA, "Balance increased correctly");
        assertEquals(initialHistorySize + 1, account.getHistory().size(), "History updated");
    }

    @Test
    @DisplayName("Apply interest multiple times → balance compounds correctly")
    void applyInterest_MultipleApplications_BalanceCompoundsCorrectly() {
        // Arrange
        account = new SavingsAccount(1000.0, 0.10);
        double expectedBalance = 1000.0;

        // Act & Assert - First application
        account.applyInterest();
        expectedBalance += expectedBalance * 0.10;
        assertEquals(expectedBalance, account.getBalance(), DELTA, "Balance after first interest");

        // Second application
        account.applyInterest();
        expectedBalance += expectedBalance * 0.10;
        assertEquals(expectedBalance, account.getBalance(), DELTA, "Balance after second interest");

        // Third application
        account.applyInterest();
        expectedBalance += expectedBalance * 0.10;
        assertEquals(expectedBalance, account.getBalance(), DELTA, "Balance after third interest");

        assertEquals(4, account.getHistory().size(), "History includes opening + 3 interest entries");
    }

    @Test
    @DisplayName("Apply interest on account with transaction history → only interest entry added")
    void applyInterest_WithExistingHistory_AddsOnlyInterestEntry() {
        // Arrange
        account.processTransaction(500.0);
        account.processTransaction(-200.0);
        int initialHistorySize = account.getHistory().size();
        double initialBalance = account.getBalance();

        // Act
        account.applyInterest();

        // Assert
        assertEquals(initialHistorySize + 1, account.getHistory().size(), "Only one entry added");
        double expectedInterest = initialBalance * account.getInterestRate();
        double expectedBalance = initialBalance + expectedInterest;
        assertEquals(expectedBalance, account.getBalance(), DELTA, "Balance updated correctly");
    }

    @ParameterizedTest
    @DisplayName("Apply interest with various rates → balance updates correctly")
    @CsvSource({
            "1000.0, 0.0, 1000.0",
            "1000.0, 0.01, 1010.0",
            "1000.0, 0.05, 1050.0",
            "1000.0, 0.10, 1100.0",
            "1000.0, 0.50, 1500.0",
            "1000.0, 1.00, 2000.0",
            "1000.0, 2.50, 3500.0"
    })
    void applyInterest_WithVariousInterestRates_BalanceUpdatesCorrectly(
            double initialBalance, double interestRate, double expectedBalanceAfterOneYear) {
        // Arrange
        account = new SavingsAccount(initialBalance, interestRate);

        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalanceAfterOneYear, account.getBalance(), DELTA,
                String.format("Balance with rate %.2f", interestRate));
    }

    @Test
    @DisplayName("Apply interest synchronously from multiple threads → thread-safe execution")
    void applyInterest_ConcurrentCalls_ThreadSafe() throws InterruptedException {
        // Arrange
        account = new SavingsAccount(1000.0, 0.01);
        int threadCount = 100;
        Thread[] threads = new Thread[threadCount];
        double expectedBalance = 1000.0;

        // Calculate expected balance after 100 applications
        for (int i = 0; i < threadCount; i++) {
            expectedBalance += expectedBalance * 0.01;
        }

        // Act
        for (int i = 0; i < threadCount; i++) {
            threads[i] = new Thread(account::applyInterest);
            threads[i].start();
        }

        for (int i = 0; i < threadCount; i++) {
            threads[i].join();
        }

        // Assert
        assertEquals(expectedBalance, account.getBalance(), 0.0001 * expectedBalance,
                "Balance after concurrent interest applications");
        assertEquals(threadCount + 1, account.getHistory().size(), "All interest entries recorded");
    }

    @Test
    @DisplayName("Get history after applyInterest → returns unmodifiable copy")
    void applyInterest_ThenGetHistory_ReturnsUnmodifiableCopy() {
        // Arrange
        int initialHistorySize = account.getHistory().size();

        // Act
        account.applyInterest();
        List<String> history = account.getHistory();

        // Assert
        assertEquals(initialHistorySize + 1, history.size(), "History contains new entry");
        assertThrows(UnsupportedOperationException.class, () -> history.add("Illegal entry"),
                "History should be unmodifiable");
    }
}

