            assertEquals(0.03, account.getInterestRate(), DELTA);
            assertEquals("Balance: 6210.00 | Transactions: 4", summary);
            assertEquals(4, history.size());
            assertTrue(history.get(0).contains("Account opened with: 5000.0"));
