            assertTrue(summary.contains("Transactions: 101")); // 1 opening + 100 deposits
        }

        @Test
        @DisplayName("Precision handling with many operations → maintains accuracy")
        void precisionHandling_manyOperations_maintainsAccuracy() {
            // Arrange
            SavingsAccount account = new SavingsAccount(0.01, 0.0001); // Very small interest rate

            // Act
            for (int i = 0; i < 1000; i++) {
                account.processTransaction(0.01);
            }
            account.applyInterest();

            // Assert
            // Starting balance: 0.01, add 1000 * 0.01 = 10.00, total = 10.01
            // Interest: 10.01 * 0.0001 = 0.001001, final = 10.011001
            assertEquals(10.011001, account.getBalance(), DELTA);
        }
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;
import org.junit.jupiter.params.provider.ValueSource;

import java.lang.reflect.Field;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class SavingsAccountTest {

    private SavingsAccount account;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(1000.0, 0.05);
    }

    @Test
    @DisplayName("getBalance after construction with initial balance → returns correct balance")
    void getBalance_AfterConstruction_ReturnsCorrectBalance() {
        // Arrange
        double expectedBalance = 1000.0;

        // Act
        double actualBalance = account.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance after multiple deposits → returns cumulative balance")
    void getBalance_AfterMultipleDeposits_ReturnsCumulativeBalance() {
        // Arrange
        account.processTransaction(500.0);
        account.processTransaction(250.0);
        double expectedBalance = 1750.0;

        // Act
        double actualBalance = account.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance after withdrawal within limits → returns updated balance")
    void getBalance_AfterWithdrawalWithinLimits_ReturnsUpdatedBalance() {
        // Arrange
        account.processTransaction(-300.0);
        double expectedBalance = 700.0;

        // Act
        double actualBalance = account.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance after interest application → returns balance with interest")
    void getBalance_AfterInterestApplication_ReturnsBalanceWithInterest() {
        // Arrange
        account.applyInterest();
        double expectedBalance = 1050.0; // 1000 + (1000 * 0.05)

        // Act
        double actualBalance = account.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance after zero transaction → returns unchanged balance")
    void getBalance_AfterZeroTransaction_ReturnsUnchangedBalance() {
        // Arrange
        account.processTransaction(0.0);
        double expectedBalance = 1000.0;

        // Act
        double actualBalance = account.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance after complex sequence of operations → returns correct final balance")
    void getBalance_AfterComplexOperations_ReturnsCorrectFinalBalance() {
        // Arrange
        account.processTransaction(200.0);
        account.applyInterest(); // On 1200 at 5% = 60 interest
        account.processTransaction(-100.0);
        account.applyInterest(); // On 1160 at 5% = 58 interest
        double expectedBalance = 1218.0; // (((1000+200)*1.05)-100)*1.05

        // Act
        double actualBalance = account.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance with floating point precision → returns precise value")
    void getBalance_WithFloatingPointPrecision_ReturnsPreciseValue() {
        // Arrange
        SavingsAccount preciseAccount = new SavingsAccount(0.1, 0.0);
        preciseAccount.processTransaction(0.2);
        // 0.1 + 0.2 should be 0.3

        // Act
        double balance = preciseAccount.getBalance();

        // Assert
        assertEquals(0.3, balance, 1e-15); // High precision assertion
    }

    @ParameterizedTest
    @ValueSource(doubles = {0.0, 0.01, 999.99, 1000.0, 1_000_000.0})
    @DisplayName("getBalance with various valid initial amounts → returns correct balance")
    void getBalance_WithVariousValidInitialAmounts_ReturnsCorrectBalance(double initialBalance) {
        // Arrange
        SavingsAccount testAccount = new SavingsAccount(initialBalance);
        double expectedBalance = initialBalance;

        // Act
        double actualBalance = testAccount.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance reflects real-time state after each transaction")
    void getBalance_ReflectsRealTimeState_AfterEachTransaction() {
        // Arrange & Act & Assert in sequence
        assertEquals(1000.0, account.getBalance(), 0.001);

        account.processTransaction(500.0);
        assertEquals(1500.0, account.getBalance(), 0.001);

        account.processTransaction(-300.0);
        assertEquals(1200.0, account.getBalance(), 0.001);

        account.applyInterest();
        assertEquals(1260.0, account.getBalance(), 0.001); // 1200 * 1.05
    }

    @Test
    @DisplayName("getBalance after constructor with only initial balance → uses default interest rate")
    void getBalance_AfterSingleArgumentConstructor_UsesDefaultInterestRate() throws Exception {
        // Arrange
        SavingsAccount defaultAccount = new SavingsAccount(500.0);
        Field interestRateField = SavingsAccount.class.getDeclaredField("interestRate");
        interestRateField.setAccessible(true);
        double defaultInterestRate = (double) interestRateField.get(defaultAccount);

        // Act
        defaultAccount.applyInterest();
        double expectedBalance = 500.0 * (1 + defaultInterestRate);
        double actualBalance = defaultAccount.getBalance();

        // Assert
        assertEquals(expectedBalance, actualBalance, 0.001);
    }

    @ParameterizedTest
    @CsvSource({
        "1000.0, 0.0, 1000.0",
        "500.0, 0.01, 505.0",
        "200.0, 0.5, 300.0",
        "0.0, 0.1, 0.0"
    })
    @DisplayName("getBalance after interest with various rates → returns correct balance")
    void getBalance_AfterInterestWithVariousRates_ReturnsCorrectBalance(double initial, double rate, double expected) {
        // Arrange
        SavingsAccount testAccount = new SavingsAccount(initial, rate);

        // Act
        testAccount.applyInterest();
        double actualBalance = testAccount.getBalance();

        // Assert
        assertEquals(expected, actualBalance, 0.001);
    }

    @Test
    @DisplayName("getBalance returns same value as stored in private field")
    void getBalance_ReturnsSameValueAsPrivateField() throws Exception {
        // Arrange
        Field balanceField = SavingsAccount.class.getDeclaredField("balance");
        balanceField.setAccessible(true);

        // Act
        double viaGetter = account.getBalance();
        double viaReflection = (double) balanceField.get(account);

        // Assert
        assertEquals(viaReflection, viaGetter, 0.0);
    }

    @Test
    @DisplayName("getBalance is independent of other getters")
    void getBalance_IndependentOfOtherGetters() {
        // Arrange
        double initialBalance = account.getBalance();
        double initialInterestRate = account.getInterestRate();
        int initialHistorySize = account.getHistory().size();

        // Act - Change state through interest application
        account.applyInterest();
        double newBalance = account.getBalance();
        double newInterestRate = account.getInterestRate();
        int newHistorySize = account.getHistory().size();

        // Assert
        assertNotEquals(initialBalance, newBalance, 0.001);
        assertEquals(initialInterestRate, newInterestRate, 0.001); // Should not change
        assertNotEquals(initialHistorySize, newHistorySize); // History increased
    }

    @Test
    @DisplayName("getBalance returns defensive copy protection → consistent state")
    void getBalance_ReturnsConsistentState_DespiteInternalChanges() throws Exception {
        // Arrange
        double initialBalance = account.getBalance();

        // Act - Directly modify internal field via reflection
        Field balanceField = SavingsAccount.class.getDeclaredField("balance");
        balanceField.setAccessible(true);
        balanceField.set(account, 9999.0);

        // Assert - Getter should reflect the changed state
        assertEquals(9999.0, account.getBalance(), 0.001);
        assertNotEquals(initialBalance, account.getBalance(), 0.001);
    }

    @Test
    @DisplayName("getBalance with maximum double value → handles extreme values")
    void getBalance_WithMaximumDoubleValue_HandlesExtremeValues() {
        // Arrange
        SavingsAccount maxAccount = new SavingsAccount(Double.MAX_VALUE, 0.0);

        // Act & Assert - Should not throw exception
        assertDoesNotThrow(() -> {
            double balance = maxAccount.getBalance();
            assertEquals(Double.MAX_VALUE, balance, 0.0);
        });
    }

    @Test
    @DisplayName("getBalance with minimum positive double value → handles extreme precision")
    void getBalance_WithMinimumPositiveDoubleValue_HandlesExtremePrecision() {
        // Arrange
        double minPositive = Double.MIN_VALUE;
        SavingsAccount minAccount = new SavingsAccount(minPositive, 0.0);

        // Act
        double balance = minAccount.getBalance();

        // Assert
        assertEquals(minPositive, balance, 0.0);
    }
}

package com.bank.logic;

