    @DisplayName("Constructor with zero interest rate → interest rate equals zero")
    void getInterestRate_ConstructorWithZeroRate_ReturnsZero() {
        // Arrange
        double initialBalance = 300.0;
        double zeroRate = 0.0;
        account = new SavingsAccount(initialBalance, zeroRate);

        // Act
        double actualInterestRate = account.getInterestRate();

        // Assert
        assertEquals(zeroRate, actualInterestRate, DELTA,
            "Constructor should accept zero interest rate");
    }

    @ParameterizedTest
    @ValueSource(doubles = {0.01, 0.1, 1.0, 10.0})
    @DisplayName("Constructor with various valid rates → interest rate correctly stored")
    void getInterestRate_ConstructorWithVariousRates_ReturnsCorrectRate(double rate) {
        // Arrange
        double initialBalance = 500.0;
        account = new SavingsAccount(initialBalance, rate);

        // Act
        double actualInterestRate = account.getInterestRate();

        // Assert
        assertEquals(rate, actualInterestRate, DELTA,
            "Constructor should correctly store interest rate: " + rate);
    }

    @Test
    @DisplayName("Constructor with negative interest rate → throws IllegalArgumentException")
    void constructor_NegativeInterestRate_ThrowsIllegalArgumentException() {
        // Arrange
        double initialBalance = 100.0;
        double negativeRate = -0.01;

        // Act & Assert
        IllegalArgumentException exception = assertThrows(
            IllegalArgumentException.class,
            () -> new SavingsAccount(initialBalance, negativeRate),
            "Constructor should reject negative interest rate"
        );

        assertEquals("Invalid initial values", exception.getMessage(),
            "Exception message should match");
    }

    @Test
    @DisplayName("Apply interest does not change stored interest rate")
    void getInterestRate_AfterApplyingInterest_ReturnsSameRate() {
        // Arrange
        double initialBalance = 1000.0;
        double originalRate = 0.03;
        account = new SavingsAccount(initialBalance, originalRate);

        // Act
        account.applyInterest();
        double actualInterestRate = account.getInterestRate();

        // Assert
        assertEquals(originalRate, actualInterestRate, DELTA,
            "Applying interest should not change the stored interest rate");
    }

    @Test
    @DisplayName("Multiple transactions do not affect interest rate")
    void getInterestRate_AfterMultipleTransactions_ReturnsSameRate() {
        // Arrange
        double initialBalance = 500.0;
        double originalRate = 0.025;
        account = new SavingsAccount(initialBalance, originalRate);

        // Act
        account.processTransaction(100.0);
        account.processTransaction(-50.0);
        account.processTransaction(200.0);
        double actualInterestRate = account.getInterestRate();

        // Assert
        assertEquals(originalRate, actualInterestRate, DELTA,
            "Transactions should not affect the interest rate");
    }

    @Test
    @DisplayName("Interest rate remains constant throughout account lifecycle")
    void getInterestRate_AccountLifecycle_ReturnsConsistentRate() {
        // Arrange
        double initialBalance = 1000.0;
        double expectedRate = 0.04;
        account = new SavingsAccount(initialBalance, expectedRate);

        // Act & Assert - Multiple checks throughout lifecycle
        assertEquals(expectedRate, account.getInterestRate(), DELTA,
            "Initial rate should be correct");

        account.processTransaction(500.0);
        assertEquals(expectedRate, account.getInterestRate(), DELTA,
            "Rate after deposit should remain unchanged");

        account.applyInterest();
        assertEquals(expectedRate, account.getInterestRate(), DELTA,
            "Rate after interest application should remain unchanged");

        account.processTransaction(-300.0);
        assertEquals(expectedRate, account.getInterestRate(), DELTA,
            "Rate after withdrawal should remain unchanged");

        // Final check
        assertEquals(expectedRate, account.getInterestRate(), DELTA,
            "Final rate check should match initial rate");
    }

    @Test
    @DisplayName("toString contains correct interest rate")
    void toString_ContainsCorrectInterestRate() {
        // Arrange
        double initialBalance = 250.0;
        double interestRate = 0.035;
        account = new SavingsAccount(initialBalance, interestRate);

        // Act
        String stringRepresentation = account.toString();

        // Assert
        assertTrue(stringRepresentation.contains("interestRate=" + interestRate),
            "toString should include the correct interest rate");
    }

    @ParameterizedTest
    @CsvSource({
        "100.0, 0.02",
        "0.0, 0.0",
        "1000.0, 0.15",
        "500.0, 1.0"
    })
    @DisplayName("Account summary does not include interest rate")
    void getAccountSummary_DoesNotIncludeInterestRate(double balance, double rate) {
        // Arrange
        account = new SavingsAccount(balance, rate);

        // Act
        String summary = account.getAccountSummary();

        // Assert
        assertFalse(summary.contains(String.valueOf(rate)),
            "Account summary should not include interest rate");
    }

    @Test
    @DisplayName("History retrieval does not expose interest rate")
    void getHistory_DoesNotContainInterestRate() {
        // Arrange
        double initialBalance = 300.0;
