        account = new SavingsAccount(initialBalance, interestRate);
        account.applyInterest();

        // Act
        List<String> history = account.getHistory();

        // Assert
        boolean containsRate = history.stream()
            .anyMatch(entry -> entry.contains(String.valueOf(interestRate)));
