import java.lang.reflect.Field;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class SavingsAccountTest {

    private SavingsAccount account;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(1000.0, 0.05);
    }

    @Test
    @DisplayName("getHistory on new account → returns list with opening entry")
    void getHistory_NewAccount_ReturnsListWithOpeningEntry() {
        // Arrange
        // Account created in setUp with initial balance 1000

        // Act
        List<String> history = account.getHistory();

        // Assert
        assertEquals(1, history.size());
        assertEquals("Account opened with: 1000.0", history.get(0));
    }

    @Test
    @DisplayName("getHistory after deposit → includes deposit transaction")
    void getHistory_AfterDeposit_IncludesDepositTransaction() {
        // Arrange
        account.processTransaction(500.0);

        // Act
        List<String> history = account.getHistory();

        // Assert
        assertEquals(2, history.size());
        assertEquals("Account opened with: 1000.0", history.get(0));
        // Note: processTransaction doesn't add to history, so only opening entry
    }

    @Test
    @DisplayName("getHistory after interest application → includes interest entry")
    void getHistory_AfterApplyInterest_IncludesInterestEntry() {
        // Arrange
        account.applyInterest();

        // Act
        List<String> history = account.getHistory();

        // Assert
        assertEquals(2, history.size());
        assertEquals("Account opened with: 1000.0", history.get(0));
        assertTrue(history.get(1).startsWith("Interest applied: "));
        assertEquals("Interest applied: 50.00", history.get(1));
    }

    @Test
    @DisplayName("getHistory after multiple operations → returns correct sequence")
    void getHistory_MultipleOperations_ReturnsCorrectSequence() {
        // Arrange
        account.processTransaction(500.0);
        account.applyInterest();
        account.processTransaction(-200.0);
        account.applyInterest();

        // Act
        List<String> history = account.getHistory();

        // Assert
        assertEquals(3, history.size());
        assertEquals("Account opened with: 1000.0", history.get(0));
        assertTrue(history.get(1).startsWith("Interest applied: "));
        assertTrue(history.get(2).startsWith("Interest applied: "));
    }

    @Test
    @DisplayName("getHistory returns copy → modifying returned list doesn't affect internal list")
    void getHistory_ReturnsCopy_ModificationsDontAffectInternalList() throws Exception {
        // Arrange
        account.applyInterest();

        // Act
        List<String> historyCopy = account.getHistory();
        historyCopy.add("Tampered entry");

        // Get history again
        List<String> historyAgain = account.getHistory();

        // Assert
        assertEquals(2, historyCopy.size());
        assertEquals(2, historyAgain.size());
        assertEquals("Account opened with: 1000.0", historyAgain.get(0));
        assertEquals("Interest applied: 50.00", historyAgain.get(1));
    }

    @Test
    @DisplayName("getHistory reflects all constructor entries → includes all opening messages")
    void getHistory_ConstructorCalls_IncludesAllOpeningMessages() {
        // Arrange
        SavingsAccount account1 = new SavingsAccount(500.0);
        SavingsAccount account2 = new SavingsAccount(750.0, 0.03);

        // Act
        List<String> history1 = account1.getHistory();
        List<String> history2 = account2.getHistory();

        // Assert
        assertEquals(1, history1.size());
        assertEquals("Account opened with: 500.0", history1.get(0));

        assertEquals(1, history2.size());
        assertEquals("Account opened with: 750.0", history2.get(0));
    }

    @Test
    @DisplayName("getHistory on zero balance account → contains correct opening message")
    void getHistory_ZeroBalanceAccount_ContainsCorrectOpeningMessage() {
        // Arrange
        SavingsAccount zeroAccount = new SavingsAccount(0.0, 0.01);

        // Act
        List<String> history = zeroAccount.getHistory();

        // Assert
        assertEquals(1, history.size());
        assertEquals("Account opened with: 0.0", history.get(0));
    }

    @Test
    @DisplayName("getHistory after multiple interest applications → shows all interest calculations")
    void getHistory_MultipleInterestApplications_ShowsAllCalculations() {
        // Arrange
        account.applyInterest(); // Balance becomes 1050
        account.applyInterest(); // Balance becomes 1102.5

        // Act
        List<String> history = account.getHistory();

        // Assert
        assertEquals(3, history.size());
        assertEquals("Account opened with: 1000.0", history.get(0));
        assertEquals("Interest applied: 50.00", history.get(1));
        assertEquals("Interest applied: 52.50", history.get(2));
    }

    @Test
    @DisplayName("getHistory with large numbers → handles formatting correctly")
    void getHistory_LargeNumbers_HandlesFormattingCorrectly() {
        // Arrange
        SavingsAccount largeAccount = new SavingsAccount(1_000_000.0, 0.1);
        largeAccount.applyInterest();

        // Act
        List<String> history = largeAccount.getHistory();

        // Assert
        assertEquals(2, history.size());
        assertEquals("Account opened with: 1000000.0", history.get(0));
        assertEquals("Interest applied: 100000.00", history.get(1));
    }

    @Test
    @DisplayName("getHistory after exception thrown → maintains existing history")
    void getHistory_AfterExceptionThrown_MaintainsExistingHistory() {
        // Arrange
        account.applyInterest(); // Add one entry
        List<String> initialHistory = account.getHistory();

        // Act - Try to withdraw more than balance
        assertThrows(InsolventException.class, () -> account.processTransaction(-2000.0));

        // Assert - History should remain unchanged
        List<String> finalHistory = account.getHistory();
        assertEquals(initialHistory, finalHistory);
        assertEquals(2, finalHistory.size());
    }

    @Test
    @DisplayName("getHistory is immutable copy → cannot modify through returned list")
    void getHistory_ImmutableCopy_CannotModifyThroughReturnedList() {
        // Act
        List<String> history = account.getHistory();

        // Assert - Should throw UnsupportedOperationException if we try to modify
        assertThrows(UnsupportedOperationException.class, () -> history.remove(0));
        assertThrows(UnsupportedOperationException.class, () -> history.add("New entry"));
        assertThrows(UnsupportedOperationException.class, () -> history.clear());
    }

    @ParameterizedTest
    @ValueSource(doubles = {0.0, 100.0, 999.999, 10000.0})
    @DisplayName("getHistory with various initial balances → always contains opening message")
    void getHistory_VariousInitialBalances_AlwaysContainsOpeningMessage(double initialBalance) {
        // Arrange
        SavingsAccount account = new SavingsAccount(initialBalance);

        // Act
        List<String> history = account.getHistory();

        // Assert
        assertEquals(1, history.size());
        assertEquals(String.format("Account opened with: %s", initialBalance), history.get(0));
    }

    @Test
    @DisplayName("getHistory with multiple accounts → each has independent history")
    void getHistory_MultipleAccounts_EachHasIndependentHistory() {
        // Arrange
        SavingsAccount account1 = new SavingsAccount(100.0);
        SavingsAccount account2 = new SavingsAccount(200.0);

        account1.applyInterest();
        account2.applyInterest();
        account2.applyInterest();

        // Act
        List<String> history1 = account1.getHistory();
        List<String> history2 = account2.getHistory();

        // Assert
        assertEquals(2, history1.size());
        assertEquals(3, history2.size());
        assertEquals("Account opened with: 100.0", history1.get(0));
        assertEquals("Account opened with: 200.0", history2.get(0));
    }

    @Test
    @DisplayName("getHistory internal list remains mutable → can add via applyInterest")
    void getHistory_InternalListRemainsMutable_CanAddViaApplyInterest() throws Exception {
        // Arrange - Get internal list via reflection to verify it's mutable
        Field historyField = SavingsAccount.class.getDeclaredField("history");
        historyField.setAccessible(true);

        @SuppressWarnings("unchecked")
        List<String> internalList = (List<String>) historyField.get(account);

        int initialSize = internalList.size();

        // Act
        account.applyInterest();
        int sizeAfterInterest = internalList.size();

        // Assert
        assertEquals(1, initialSize);
        assertEquals(2, sizeAfterInterest);
        assertEquals("Account opened with: 1000.0", internalList.get(0));
        assertEquals("Interest applied: 50.00", internalList.get(1));
    }
}

