        // Assert
        String expected = "SavingsAccount{balance=1250.5, interestRate=0.02}";
        assertEquals(expected, result, "String representation should reflect updated balance");
    }

    @Test
    @DisplayName("toString after applying interest → returns updated balance in string")
    void toString_AfterInterestApplication_ReturnsUpdatedBalance() {
        // Arrange
        account = new SavingsAccount(1000.0, 0.05);
        account.applyInterest();

        // Act
        String result = account.toString();

        // Assert
        String expected = "SavingsAccount{balance=1050.0, interestRate=0.05}";
        assertEquals(expected, result, "String representation should reflect interest application");
    }

    @Test
    @DisplayName("toString with zero balance → returns formatted string with zero values")
    void toString_WithZeroBalance_ReturnsCorrectFormat() {
        // Arrange
        account = new SavingsAccount(0.0, 0.0);

        // Act
        String result = account.toString();

        // Assert
        String expected = "SavingsAccount{balance=0.0, interestRate=0.0}";
        assertEquals(expected, result, "String representation should handle zero values correctly");
    }

    @Test
    @DisplayName("toString with maximum double values → returns formatted string with correct representation")
    void toString_WithMaximumDoubleValues_ReturnsCorrectFormat() {
        // Arrange
        account = new SavingsAccount(Double.MAX_VALUE, Double.MAX_VALUE);

        // Act
        String result = account.toString();

        // Assert
        String expected = String.format("SavingsAccount{balance=%s, interestRate=%s}", 
                                       Double.MAX_VALUE, Double.MAX_VALUE);
        assertEquals(expected, result, "String representation should handle maximum double values");
    }

    @Test
    @DisplayName("toString with small positive balance and rate → returns formatted string with correct precision")
    void toString_WithSmallPositiveValues_ReturnsCorrectFormat() {
        // Arrange
        account = new SavingsAccount(0.001, 0.0001);

        // Act
        String result = account.toString();

        // Assert
        String expected = "SavingsAccount{balance=0.001, interestRate=1.0E-4}";
        assertEquals(expected, result, "String representation should handle small positive values");
    }

    @ParameterizedTest
    @CsvSource({
        "123.456, 0.0789, 'SavingsAccount{balance=123.456, interestRate=0.0789}'",
        "999.999, 0.001, 'SavingsAccount{balance=999.999, interestRate=0.001}'",
        "1.0, 1.0, 'SavingsAccount{balance=1.0, interestRate=1.0}'"
    })
    @DisplayName("toString with various valid inputs → returns correct formatted string")
    void toString_WithVariousValidInputs_ReturnsCorrectFormat(double balance, double rate, String expected) {
        // Arrange
        account = new SavingsAccount(balance, rate);

        // Act
        String result = account.toString();

        // Assert
        assertEquals(expected, result, "String representation should match expected format for given inputs");
    }

    @Test
    @DisplayName("toString after multiple state changes → returns current state representation")
    void toString_AfterMultipleOperations_ReturnsCurrentState() {
        // Arrange
        account = new SavingsAccount(2000.0, 0.03);
        account.processTransaction(-500.0);
        account.applyInterest();
        account.processTransaction(100.0);

        // Act
        String result = account.toString();

        // Assert
        // Calculate expected: (2000-500)=1500, interest=1500*0.03=45, balance=1500+45+100=1645
        String expected = "SavingsAccount{balance=1645.0, interestRate=0.03}";
        assertEquals(expected, result, "String representation should reflect final state after all operations");
    }

    @Test
    @DisplayName("toString format verification → contains all required components")
    void toString_FormatVerification_ContainsRequiredComponents() {
        // Arrange
        account = new SavingsAccount(500.0, 0.025);

        // Act
        String result = account.toString();

        // Assert
        assertTrue(result.startsWith("SavingsAccount{"), "Should start with class name and opening brace");
        assertTrue(result.contains("balance="), "Should contain balance label");
        assertTrue(result.contains("interestRate="), "Should contain interestRate label");
        assertTrue(result.endsWith("}"), "Should end with closing brace");
        assertTrue(result.contains("500.0"), "Should contain balance value");
        assertTrue(result.contains("0.025"), "Should contain interest rate value");
    }

    @Test
    @DisplayName("toString consistency → multiple calls return identical result")
    void toString_MultipleCalls_ReturnsConsistentResult() {
        // Arrange
        account = new SavingsAccount(750.25, 0.015);

        // Act
        String firstCall = account.toString();
        String secondCall = account.toString();
        String thirdCall = account.toString();

        // Assert
        assertEquals(firstCall, secondCall, "Multiple toString calls should return identical strings");
        assertEquals(secondCall, thirdCall, "Multiple toString calls should return identical strings");
        assertEquals(firstCall, thirdCall, "Multiple toString calls should return identical strings");
    }

    @Test
    @DisplayName("toString after reflection field modification → returns updated values")
    void toString_AfterReflectionFieldModification_ReturnsUpdatedValues() throws Exception {
        // Arrange
        account = new SavingsAccount(100.0, 0.01);

        Field balanceField = SavingsAccount.class.getDeclaredField("balance");
        balanceField.setAccessible(true);
        balanceField.set(account, 999.99);

        Field rateField = SavingsAccount.class.getDeclaredField("interestRate");
        rateField.setAccessible(true);
        rateField.set(account, 0.099);

        // Act
        String result = account.toString();

        // Assert
        String expected = "SavingsAccount{balance=999.99, interestRate=0.099}";
        assertEquals(expected, result, "String representation should reflect field values even after reflection modification");
    }
}

