package com.bank.logic;

import org.junit.jupiter.api.*;
import org.junit.jupiter.api.function.Executable;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;
import org.junit.jupiter.params.provider.ValueSource;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.PrintStream;
import java.lang.reflect.Method;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.*;

@DisplayName("Main Class - handleDeposit Method Tests")
class MainTest {

    private final ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
    private final PrintStream originalOut = System.out;
    private final Scanner mockScanner;
    private SavingsAccount testAccount;

    // Reflection setup for private method
    private Method handleDepositMethod;

    public MainTest() throws Exception {
        handleDepositMethod = Main.class.getDeclaredMethod(
            "handleDeposit", Scanner.class, SavingsAccount.class
        );
        handleDepositMethod.setAccessible(true);

        // Create a scanner that we'll reset per test
        mockScanner = new Scanner(new ByteArrayInputStream("".getBytes()));
    }

    @BeforeEach
    void setUp() {
        System.setOut(new PrintStream(outputStream));
        testAccount = new SavingsAccount(1000.0);
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
        outputStream.reset();
    }

    private void setScannerInput(String input) {
        ByteArrayInputStream inputStream = new ByteArrayInputStream(input.getBytes());
        mockScanner.close();
        Thread.currentThread().setContextClassLoader(getClass().getClassLoader());
        mockScanner = new Scanner(inputStream);
    }

    @Test
    @DisplayName("Valid positive deposit → balance increases, success message printed")
    void handleDeposit_validPositiveAmount_depositsSuccessfully() throws Exception {
        // Arrange
        setScannerInput("500.0\n");
        double initialBalance = testAccount.getAccountSummary().contains("Balance") ?
            extractBalanceFromSummary(testAccount.getAccountSummary()) : 1000.0;

        // Act
        handleDepositMethod.invoke(null, mockScanner, testAccount);
        String output = outputStream.toString();

        // Assert
        assertAll(
            () -> assertTrue(output.contains("Enter deposit amount: "),
                "Should prompt for deposit amount"),
            () -> assertTrue(output.contains("Deposit successful."),
                "Should print success message"),
            () -> assertFalse(output.contains("Amount must be positive."),
                "Should NOT show error message"),
            () -> {
                // Verify transaction was processed
                // Since we can't directly check balance, verify no exception thrown
                assertDoesNotThrow(() -> 
                    handleDepositMethod.invoke(null, mockScanner, testAccount),
                    "Should process valid deposit without error"
                );
            }
        );
    }

    @ParameterizedTest
    @ValueSource(strings = {"0.0", "-0.1", "-100.0", "-999999.99"})
    @DisplayName("Deposit zero or negative amount → shows error, no deposit occurs")
    void handleDeposit_zeroOrNegativeAmount_showsError(String inputAmount) throws Exception {
        // Arrange
        setScannerInput(inputAmount + "\n");
        String initialSummary = testAccount.getAccountSummary();

        // Act
        handleDepositMethod.invoke(null, mockScanner, testAccount);
        String output = outputStream.toString();

        // Assert
        assertAll(
            () -> assertTrue(output.contains("Enter deposit amount: "),
                "Should prompt for deposit amount"),
            () -> assertTrue(output.contains("Amount must be positive."),
                "Should show error message for amount: " + inputAmount),
            () -> assertFalse(output.contains("Deposit successful."),
                "Should NOT print success message for amount: " + inputAmount),
            () -> assertEquals(initialSummary, testAccount.getAccountSummary(),
                "Account summary should remain unchanged")
        );
    }

    @Test
    @DisplayName("Deposit with invalid non-numeric input then valid → retries and succeeds")
    void handleDeposit_invalidThenValidInput_processesCorrectly() throws Exception {
        // Arrange
        setScannerInput("invalid\nnot-a-number\n500.0\n");
        String initialSummary = testAccount.getAccountSummary();

        // Act
        handleDepositMethod.invoke(null, mockScanner, testAccount);
        String output = outputStream.toString();

        // Assert
        assertAll(
            () -> assertTrue(output.contains("Invalid input. Please enter a valid number."),
                "Should show error for invalid input"),
            () -> assertTrue(output.contains("Deposit successful."),
                "Should eventually process valid deposit"),
            () -> {
                // Count occurrences to ensure retry logic works
                String[] lines = output.split("\n");
                long promptCount = java.util.Arrays.stream(lines)
                    .filter(line -> line.contains("Enter deposit amount:"))
                    .count();
                assertTrue(promptCount >= 3, "Should prompt at least 3 times for retries");
            }
        );
    }

    @ParameterizedTest
    @CsvSource({
        "0.01, true",
        "1.0, true",
        "999999.99, true",
        "1000000.0, true"
    })
    @DisplayName("Boundary value deposits → processes correctly based on amount validity")
    void handleDeposit_boundaryValues_processesAppropriately(
            String amount, String shouldSucceed) throws Exception {
        // Arrange
        setScannerInput(amount + "\n");
        boolean expectedSuccess = Boolean.parseBoolean(shouldSucceed);

        // Act
        handleDepositMethod.invoke(null, mockScanner, testAccount);
        String output = outputStream.toString();

        // Assert
        if (expectedSuccess) {
            assertAll(
                () -> assertTrue(output.contains("Deposit successful."),
                    "Should succeed for amount: " + amount),
                () -> assertFalse(output.contains("Amount must be positive."),
                    "Should not show error for valid amount: " + amount)
            );
        } else {
            assertAll(
                () -> assertTrue(output.contains("Amount must be positive."),
                    "Should show error for amount: " + amount),
                () -> assertFalse(output.contains("Deposit successful."),
                    "Should not succeed for invalid amount: " + amount)
            );
        }
    }

    @Test
    @DisplayName("Deposit when processTransaction throws InsolventException → exception propagates")
    void handleDeposit_whenProcessTransactionThrows_exceptionPropagates() throws Exception {
        // Arrange
        setScannerInput("500.0\n");

        // Create a mock account that throws InsolventException
        SavingsAccount throwingAccount = new SavingsAccount(1000.0) {
            @Override
            public void processTransaction(double amount) throws InsolventException {
                throw new InsolventException("Simulated exception for testing");
            }
        };

        // Act & Assert
        Executable depositAction = () -> 
            handleDepositMethod.invoke(null, mockScanner, throwingAccount);

        Exception exception = assertThrows(Exception.class, depositAction,
            "Should propagate InsolventException");

        // Check it's the wrapped InsolventException
        assertTrue(exception.getCause() instanceof InsolventException,
            "Cause should be InsolventException");
    }

    @Test
