        for (String amount : amounts) {
            outputStream.reset();
            setScannerInput(amount + "\n");

            // Act
            handleDepositMethod.invoke(null, mockScanner, testAccount);
            String output = outputStream.toString();

            // Assert each deposit
            assertAll(
