    }

    @Test
    @DisplayName("Deposit with scientific notation input → handles correctly")
    void handleDeposit_scientificNotationInput_processesCorrectly() throws Exception {
        // Arrange
        setScannerInput("1.0E3\n"); // 1000 in scientific notation

        // Act
        handleDepositMethod.invoke(null, mockScanner, testAccount);
        String output = outputStream.toString();

        // Assert
        // Scanner.nextDouble() should parse scientific notation
        assertAll(
            () -> assertTrue(output.contains("Deposit successful."),
                "Should process scientific notation as valid number"),
            () -> assertFalse(output.contains("Invalid input"),
                "Should not show invalid input error for scientific notation")
        );
    }

    @Test
    @DisplayName("Deposit with maximum double value → processes without exception")
    void handleDeposit_maxDoubleValue_processesWithoutError() throws Exception {
        // Arrange
        setScannerInput(String.valueOf(Double.MAX_VALUE) + "\n");

        // Act & Assert
        assertDoesNotThrow(() -> 
            handleDepositMethod.invoke(null, mockScanner, testAccount),
            "Should handle maximum double value without throwing"
        );

        String output = outputStream.toString();
        assertTrue(output.contains("Deposit successful.") || 
                  output.contains("Amount must be positive."),
            "Should either succeed or show appropriate error");
    }

    @Test
    @DisplayName("Deposit with exactly zero → shows error message")
    void handleDeposit_exactlyZero_showsErrorMessage() throws Exception {
        // Arrange
        setScannerInput("0\n");

        // Act
        handleDepositMethod.invoke(null, mockScanner, testAccount);
        String output = outputStream.toString();

        // Assert
        assertAll(
            () -> assertTrue(output.contains("Amount must be positive."),
                "Should show error for exactly zero"),
            () -> assertFalse(output.contains("Deposit successful."),
                "Should not succeed for zero amount")
        );
    }

    @Test
    @DisplayName("Deposit with whitespace input → retries until valid")
    void handleDeposit_whitespaceInput_retriesUntilValid() throws Exception {
        // Arrange
        setScannerInput("   \n  \t\n 500.0 \n");

        // Act
        handleDepositMethod.invoke(null, mockScanner, testAccount);
        String output = outputStream.toString();

        // Assert
        assertAll(
            () -> assertTrue(output.contains("Invalid input. Please enter a valid number."),
                "Should show error for whitespace input"),
            () -> assertTrue(output.contains("Deposit successful."),
                "Should eventually process valid input"),
            () -> {
                // Verify multiple prompts
                String[] lines = output.split("\n");
                long promptCount = java.util.Arrays.stream(lines)
                    .filter(line -> line.contains("Enter deposit amount:"))
                    .count();
                assertTrue(promptCount >= 3, "Should prompt multiple times for retries");
            }
        );
    }

    // Helper method to extract balance from account summary string
    private double extractBalanceFromSummary(String summary) {
        try {
            // Simple extraction - assuming format "Balance: $1000.00"
            String[] parts = summary.split("\\$");
            if (parts.length > 1) {
                return Double.parseDouble(parts[1].trim());
            }
        } catch (Exception e) {
            // Fallback
        }
        return 1000.0; // Default for testing
    }
}

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.PrintStream;
import java.lang.reflect.Method;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.*;

class MainTest {

    private final ByteArrayOutputStream outContent = new ByteArrayOutputStream();
    private final ByteArrayOutputStream errContent = new ByteArrayOutputStream();
    private final PrintStream originalOut = System.out;
    private final PrintStream originalErr = System.err;
    private SavingsAccount testAccount;
    private Method handleWithdrawMethod;

    @BeforeEach
    void setUp() throws Exception {
        System.setOut(new PrintStream(outContent));
        System.setErr(new PrintStream(errContent));
        testAccount = new SavingsAccount(1000.0);

        // Use reflection to access private handleWithdraw method
        handleWithdrawMethod = Main.class.getDeclaredMethod(
            "handleWithdraw", Scanner.class, SavingsAccount.class);
        handleWithdrawMethod.setAccessible(true);
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
        System.setErr(originalErr);
        handleWithdrawMethod.setAccessible(false);
    }

    private String getConsoleOutput() {
        return outContent.toString().replaceAll("\r\n", "\n");
    }

    private Scanner createScanner(String input) {
        ByteArrayInputStream in = new ByteArrayInputStream(input.getBytes());
        return new Scanner(in);
    }

    private void invokeHandleWithdraw(Scanner scanner, SavingsAccount account) throws Exception {
        handleWithdrawMethod.invoke(null, scanner, account);
    }

    @Test
    @DisplayName("Valid withdrawal within balance → succeeds with confirmation message")
    void testValidWithdrawalWithinBalance() throws Exception {
        // Arrange
        String input = "200\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        String output = getConsoleOutput();
        assertAll(
            () -> assertEquals(initialBalance - 200, testAccount.getBalance(), 0.001,
                "Balance should be reduced by withdrawal amount"),
            () -> assertTrue(output.contains("Withdrawal successful."),
                "Should display success message"),
            () -> assertFalse(output.contains("Amount must be positive."),
                "Should not show validation error"),
            () -> assertFalse(output.contains("Invalid input"),
                "Should not show input format error")
        );
    }

    @Test
    @DisplayName("Withdrawal of exact balance → succeeds with confirmation")
    void testWithdrawalExactBalance() throws Exception {
        // Arrange
        String input = "1000\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        String output = getConsoleOutput();
        assertAll(
            () -> assertEquals(0, testAccount.getBalance(), 0.001,
                "Balance should be zero after exact withdrawal"),
            () -> assertTrue(output.contains("Withdrawal successful."),
                "Should display success message")
        );
    }

    @ParameterizedTest
    @ValueSource(doubles = {-100.0, -0.01, -1.0})
    @DisplayName("Negative withdrawal amount → shows validation error and does not change balance")
    void testNegativeWithdrawalAmount(double amount) throws Exception {
        // Arrange
        String input = amount + "\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        String output = getConsoleOutput();
        assertAll(
            () -> assertEquals(initialBalance, testAccount.getBalance(), 0.001,
                "Balance should remain unchanged"),
            () -> assertTrue(output.contains("Amount must be positive."),
                "Should display validation error"),
            () -> assertFalse(output.contains("Withdrawal successful."),
                "Should not show success message")
        );
    }

    @Test
    @DisplayName("Zero withdrawal amount → shows validation error and does not change balance")
    void testZeroWithdrawalAmount() throws Exception {
        // Arrange
        String input = "0\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        String output = getConsoleOutput();
        assertAll(
            () -> assertEquals(initialBalance, testAccount.getBalance(), 0.001,
                "Balance should remain unchanged"),
            () -> assertTrue(output.contains("Amount must be positive."),
                "Should display validation error for zero"),
            () -> assertFalse(output.contains("Withdrawal successful."),
                "Should not show success message")
        );
    }

    @Test
    @DisplayName("Withdrawal exceeding balance → throws InsolventException")
    void testWithdrawalExceedingBalance() throws Exception {
        // Arrange
        String input = "1500\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act & Assert
        Exception exception = assertThrows(Exception.class, 
            () -> invokeHandleWithdraw(scanner, testAccount),
            "Should throw InsolventException");

        // Unwrap the InvocationTargetException to get the actual InsolventException
        Throwable cause = exception.getCause();
        assertNotNull(cause, "Should have a cause");
        assertEquals(InsolventException.class, cause.getClass(),
            "Should be InsolventException");

        // Verify balance unchanged
        assertEquals(initialBalance, testAccount.getBalance(), 0.001,
            "Balance should remain unchanged after failed withdrawal");

        // Verify error message was printed
        assertTrue(errContent.toString().contains("Error: "),
            "Error should be printed to stderr");
    }

    @Test
    @DisplayName("Large withdrawal amount → throws InsolventException")
    void testLargeWithdrawalAmount() throws Exception {
        // Arrange
        String input = "999999\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act & Assert
        Exception exception = assertThrows(Exception.class,
            () -> invokeHandleWithdraw(scanner, testAccount));

        Throwable cause = exception.getCause();
        assertEquals(InsolventException.class, cause.getClass());
        assertEquals(initialBalance, testAccount.getBalance(), 0.001);
    }

    @Test
    @DisplayName("Invalid input (non-numeric) followed by valid withdrawal → retries and succeeds")
    void testInvalidInputThenValidWithdrawal() throws Exception {
        // Arrange
        String input = "abc\n-100\n0\n200\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        String output = getConsoleOutput();
        assertAll(
            () -> assertEquals(initialBalance - 200, testAccount.getBalance(), 0.001,
                "Should process final valid input"),
            () -> assertTrue(output.contains("Invalid input"),
                "Should show invalid input message for non-numeric"),
            () -> assertTrue(output.contains("Amount must be positive."),
                "Should show validation error for negative input"),
            () -> assertTrue(output.contains("Withdrawal successful."),
                "Should eventually succeed")
        );
    }

    @Test
    @DisplayName("Multiple invalid inputs then valid withdrawal → eventually succeeds")
    void testMultipleInvalidInputsThenValid() throws Exception {
        // Arrange
        String input = "xyz\n!@#\n-50\n0\n100\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        String output = getConsoleOutput();
        int invalidInputCount = output.split("Invalid input").length - 1;
        int validationErrorCount = output.split("Amount must be positive").length - 1;

        assertAll(
            () -> assertEquals(initialBalance - 100, testAccount.getBalance(), 0.001),
            () -> assertEquals(2, invalidInputCount, "Should handle 2 non-numeric inputs"),
            () -> assertEquals(2, validationErrorCount, "Should handle 2 invalid amounts"),
            () -> assertTrue(output.contains("Withdrawal successful."))
        );
    }

    @Test
    @DisplayName("Withdrawal with decimal amount → processes correctly")
    void testDecimalWithdrawalAmount() throws Exception {
        // Arrange
        String input = "123.45\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        assertEquals(initialBalance - 123.45, testAccount.getBalance(), 0.001,
            "Should handle decimal amounts correctly");
        assertTrue(getConsoleOutput().contains("Withdrawal successful."));
    }

    @Test
    @DisplayName("Withdrawal with maximum double precision → processes correctly")
    void testMaximumPrecisionWithdrawal() throws Exception {
        // Arrange
        String input = "0.0001\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        assertEquals(initialBalance - 0.0001, testAccount.getBalance(), 0.00001,
            "Should handle small decimal amounts");
        assertTrue(getConsoleOutput().contains("Withdrawal successful."));
    }

    @Test
    @DisplayName("Withdrawal with whitespace input → handles correctly")
    void testWhitespaceInput() throws Exception {
        // Arrange
        String input = "   300   \n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        assertEquals(initialBalance - 300, testAccount.getBalance(), 0.001,
            "Should trim and process whitespace input");
        assertTrue(getConsoleOutput().contains("Withdrawal successful."));
    }

    @Test
    @DisplayName("Empty input followed by valid withdrawal → retries and succeeds")
    void testEmptyInputThenValid() throws Exception {
        // Arrange
        String input = "\n500\n";
        Scanner scanner = createScanner(input);
        double initialBalance = testAccount.getBalance();

        // Act
        invokeHandleWithdraw(scanner, testAccount);

        // Assert
        String output = getConsoleOutput();
        assertAll(
            () -> assertEquals(initialBalance - 500, testAccount.getBalance(), 0.001),
            () -> assertTrue(output.contains("Invalid input"),
                "Should handle empty line as invalid"),
            () -> assertTrue(output.contains("Withdrawal successful."))
        );
    }
}

package com.bank.logic;

import org.junit.jupiter.api.*;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.Arguments;
import org.junit.jupiter.params.provider.CsvSource;
import org.junit.jupiter.params.provider.MethodSource;
import org.junit.jupiter.params.provider.ValueSource;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.io.PrintStream;
import java.lang.reflect.Method;
import java.util.Scanner;
import java.util.stream.Stream;

import static org.junit.jupiter.api.Assertions.*;

@DisplayName("Main Class Unit Tests")
class MainTest {

    private final ByteArrayOutputStream outputStreamCaptor = new ByteArrayOutputStream();
    private final PrintStream originalOut = System.out;
    private final InputStream originalIn = System.in;

    @BeforeEach
    void setUp() {
        System.setOut(new PrintStream(outputStreamCaptor));
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
        System.setIn(originalIn);
    }

    private String getOutput() {
        return outputStreamCaptor.toString().replace("\r\n", "\n");
    }

    private void provideInput(String data) {
        System.setIn(new ByteArrayInputStream(data.getBytes()));
    }

    // Test readInt method via reflection
    private int invokeReadInt(Scanner scanner, String message) throws Exception {
        Method method = Main.class.getDeclaredMethod("readInt", Scanner.class, String.class);
        method.setAccessible(true);
        return (int) method.invoke(null, scanner, message);
    }

    @Nested
    @DisplayName("readInt Method Tests")
    class ReadIntTests {

        @Test
        @DisplayName("Valid integer input → returns the integer value")
        void readInt_validIntegerInput_returnsIntegerValue() throws Exception {
            // Arrange
            String input = "42";
            provideInput(input);
            Scanner scanner = new Scanner(System.in);
            String prompt = "Enter choice: ";

            // Act
            int result = invokeReadInt(scanner, prompt);

            // Assert
            assertEquals(42, result);
            assertTrue(getOutput().contains(prompt));
        }

        @ParameterizedTest
        @ValueSource(strings = {"-5", "0", "1000000", "999999999"})
        @DisplayName("Various valid integers → returns correct integer values")
        void readInt_variousValidIntegers_returnsCorrectValues(String input) throws Exception {
            // Arrange
            provideInput(input);
            Scanner scanner = new Scanner(System.in);
            int expected = Integer.parseInt(input);

            // Act
            int result = invokeReadInt(scanner, "Test: ");

            // Assert
            assertEquals(expected, result);
        }

        @Test
        @DisplayName("Multiple invalid inputs followed by valid integer → returns valid integer after retries")
        void readInt_multipleInvalidThenValid_returnsIntegerAfterRetries() throws Exception {
            // Arrange
            String input = "abc\n12.34\ninvalid\n42";
            provideInput(input);
            Scanner scanner = new Scanner(System.in);
            String prompt = "Enter number: ";

            // Act
            int result = invokeReadInt(scanner, prompt);

            // Assert
            assertEquals(42, result);
            String output = getOutput();
            assertTrue(output.contains(prompt));
            // Should display error message 3 times for invalid inputs
            assertTrue(output.contains("Invalid input. Please enter a number."));
            // Count occurrences of the prompt (should be 4 times: 3 invalid + 1 valid)
            long promptCount = output.lines().filter(line -> line.contains(prompt)).count();
            assertTrue(promptCount >= 4);
        }

        @Test
        @DisplayName("Empty input followed by valid integer → handles empty line gracefully")
        void readInt_emptyInputThenValid_handlesGracefully() throws Exception {
            // Arrange
            String input = "\n\n\n25";
            provideInput(input);
            Scanner scanner = new Scanner(System.in);

            // Act
            int result = invokeReadInt(scanner, "Choice: ");

            // Assert
            assertEquals(25, result);
            String output = getOutput();
            assertTrue(output.contains("Invalid input. Please enter a number."));
        }

        @Test
        @DisplayName("Input exceeds integer range followed by valid → handles large number gracefully")
        void readInt_outOfRangeThenValid_handlesGracefully() throws Exception {
            // Arrange
            String input = "999999999999999999999999\n50";
            provideInput(input);
            Scanner scanner = new Scanner(System.in);

            // Act
            int result = invokeReadInt(scanner, "Enter: ");

            // Assert
            assertEquals(50, result);
            String output = getOutput();
            assertTrue(output.contains("Invalid input. Please enter a number."));
        }

        @Test
        @DisplayName("Mixed whitespace with valid integer → returns trimmed integer")
        void readInt_whitespaceWithInteger_returnsTrimmedInteger() throws Exception {
            // Arrange
            String input = "   75   ";
            provideInput(input);
            Scanner scanner = new Scanner(System.in);

            // Act
            int result = invokeReadInt(scanner, "Value: ");

            // Assert
            assertEquals(75, result);
        }

        @Test
        @DisplayName("Boundary value at Integer.MAX_VALUE → handles correctly if entered")
        void readInt_maxIntegerValue_handlesCorrectly() throws Exception {
            // Arrange
            String input = String.valueOf(Integer.MAX_VALUE);
            provideInput(input);
            Scanner scanner = new Scanner(System.in);

            // Act
            int result = invokeReadInt(scanner, "Max: ");

            // Assert
            assertEquals(Integer.MAX_VALUE, result);
        }

        @Test
        @DisplayName("Boundary value at Integer.MIN_VALUE → handles correctly if entered")
        void readInt_minIntegerValue_handlesCorrectly() throws Exception {
            // Arrange
            String input = String.valueOf(Integer.MIN_VALUE);
            provideInput(input);
            Scanner scanner = new Scanner(System.in);

            // Act
            int result = invokeReadInt(scanner, "Min: ");

            // Assert
            assertEquals(Integer.MIN_VALUE, result);
        }

        @ParameterizedTest
        @CsvSource({
            "abc, 'Invalid input. Please enter a number.'",
            "12.5, 'Invalid input. Please enter a number.'",
            "true, 'Invalid input. Please enter a number.'",
            "1e10, 'Invalid input. Please enter a number.'"
        })
        @DisplayName("Various invalid inputs → displays appropriate error message")
        void readInt_variousInvalidInputs_displaysErrorMessage(String input, String expectedMessage) throws Exception {
            // Arrange
            provideInput(input + "\n100");
            Scanner scanner = new Scanner(System.in);

            // Act
            invokeReadInt(scanner, "Test: ");

            // Assert
            String output = getOutput();
            assertTrue(output.contains(expectedMessage));
        }

        @Test
        @DisplayName("Input with special characters → rejects and prompts again")
        void readInt_specialCharacters_rejectsAndPromptsAgain() throws Exception {
            // Arrange
            String input = "@#$%\n&\n*\n100";
            provideInput(input);
            Scanner scanner = new Scanner(System.in);

            // Act
            int result = invokeReadInt(scanner, "Input: ");

            // Assert
            assertEquals(100, result);
            String output = getOutput();
            // Should display error message for each invalid input
            long errorCount = output.lines()
                .filter(line -> line.contains("Invalid input. Please enter a number."))
                .count();
            assertTrue(errorCount >= 3);
        }

        @Test
        @DisplayName("Single invalid then immediate valid → returns valid integer")
        void readInt_oneInvalidThenValid_returnsValidInteger() throws Exception {
            // Arrange
            String input = "not-a-number\n7";
            provideInput(input);
            Scanner scanner = new Scanner(System.in);

            // Act
            int result = invokeReadInt(scanner, "Prompt: ");

            // Assert
            assertEquals(7, result);
            String output = getOutput();
            assertTrue(output.contains("Invalid input. Please enter a number."));
            // Should contain prompt exactly twice (once for invalid, once for valid)
            assertTrue(output.contains("Prompt: "));
        }
    }

    // Helper method source for parameterized tests
    private static Stream<Arguments> provideInvalidInputs() {
        return Stream.of(
            Arguments.of("abc", "text input"),
            Arguments.of("12.34", "decimal number"),
            Arguments.of("", "empty input"),
            Arguments.of("   ", "whitespace only"),
            Arguments.of("1.2e3", "scientific notation"),
            Arguments.of("12,34", "comma decimal"),
            Arguments.of("100-", "trailing character"),
            Arguments.of("+100", "plus sign"),
            Arguments.of("100L", "type suffix"),
            Arguments.of("0x1A", "hexadecimal"),
            Arguments.of("0777", "octal"),
            Arguments.of("1_000", "underscore separator")
        );
    }

    @ParameterizedTest
    @MethodSource("provideInvalidInputs")
    @DisplayName("Invalid input patterns followed by valid integer → recovers and returns valid integer")
    void readInt_variousInvalidPatternsThenValid_recoversAndReturnsValid(
            String invalidInput, String description) throws Exception {
        // Arrange
        provideInput(invalidInput + "\n42");
        Scanner scanner = new Scanner(System.in);

        // Act
        int result = invokeReadInt(scanner, "Enter: ");

        // Assert
        assertEquals(42, result, "Failed for: " + description);
        String output = getOutput();
        assertTrue(output.contains("Invalid input. Please enter a number."),
            "Should display error for: " + description);
    }
}

