package com.bank.logic;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.NullAndEmptySource;
import org.junit.jupiter.params.provider.ValueSource;

import static org.junit.jupiter.api.Assertions.*;

class InsolventExceptionTest {

    @Test
    @DisplayName("Constructor with standard message → creates exception with correct message")
    void constructor_StandardMessage_CreatesExceptionWithCorrectMessage() {
        // Arrange
        final String expectedMessage = "Insufficient funds for transaction";

        // Act
        InsolventException exception = new InsolventException(expectedMessage);

        // Assert
        assertEquals(expectedMessage, exception.getMessage());
        assertNull(exception.getCause());
    }

    @Test
    @DisplayName("Constructor with detailed message → creates exception with formatted message")
    void constructor_DetailedMessage_CreatesExceptionWithFormattedMessage() {
        // Arrange
        final String expectedMessage = "Account 12345 has balance 50.00 but attempted withdrawal of 100.00";

        // Act
        InsolventException exception = new InsolventException(expectedMessage);

        // Assert
        assertEquals(expectedMessage, exception.getMessage());
    }

    @ParameterizedTest
    @NullAndEmptySource
    @DisplayName("Constructor with null or empty message → creates exception with provided message")
    void constructor_NullOrEmptyMessage_CreatesExceptionWithProvidedMessage(String message) {
        // Arrange & Act
        InsolventException exception = new InsolventException(message);

        // Assert
        assertEquals(message, exception.getMessage());
    }

    @Test
    @DisplayName("Constructor with whitespace-only message → creates exception with whitespace message")
    void constructor_WhitespaceOnlyMessage_CreatesExceptionWithWhitespaceMessage() {
        // Arrange
        final String expectedMessage = "   ";

        // Act
        InsolventException exception = new InsolventException(expectedMessage);

        // Assert
        assertEquals(expectedMessage, exception.getMessage());
    }

    @ParameterizedTest
    @ValueSource(strings = {
        "Short",
        "A very long message that contains multiple words and punctuation! Does it work? Yes, it should.",
        "Special chars: !@#$%^&*()",
        "Unicode: €¥£©®",
        "Multi\nline\nmessage"
    })
    @DisplayName("Constructor with various string formats → creates exception with exact message")
    void constructor_VariousStringFormats_CreatesExceptionWithExactMessage(String message) {
        // Arrange & Act
        InsolventException exception = new InsolventException(message);

        // Assert
        assertEquals(message, exception.getMessage());
    }

    @Test
    @DisplayName("Exception type check → extends RuntimeException")
    void exceptionTypeCheck_ExtendsRuntimeException() {
        // Arrange
        InsolventException exception = new InsolventException("test");

        // Assert
        assertTrue(exception instanceof RuntimeException);
        assertEquals(InsolventException.class.getSuperclass(), RuntimeException.class);
    }

    @Test
    @DisplayName("Throwing and catching → preserves message and stack trace")
    void throwingAndCatching_PreservesMessageAndStackTrace() {
        // Arrange
        final String expectedMessage = "Transaction failed due to insolvency";
        InsolventException thrownException = null;

        try {
            // Act - Throw the exception
            throw new InsolventException(expectedMessage);
        } catch (InsolventException e) {
            thrownException = e;
        }

        // Assert
        assertNotNull(thrownException);
        assertEquals(expectedMessage, thrownException.getMessage());
        assertTrue(thrownException.getStackTrace().length > 0);
    }

    @Test
    @DisplayName("Default runtime exception behavior → no suppressed exceptions by default")
    void defaultRuntimeExceptionBehavior_NoSuppressedExceptionsByDefault() {
        // Arrange & Act
        InsolventException exception = new InsolventException("test");

        // Assert
        assertEquals(0, exception.getSuppressed().length);
    }

    @Test
    @DisplayName("Multiple instantiations → independent exception instances")
    void multipleInstantiations_IndependentExceptionInstances() {
        // Arrange
        final String message1 = "First exception";
        final String message2 = "Second exception";

        // Act
        InsolventException exception1 = new InsolventException(message1);
        InsolventException exception2 = new InsolventException(message2);

        // Assert
        assertNotSame(exception1, exception2);
        assertEquals(message1, exception1.getMessage());
        assertEquals(message2, exception2.getMessage());
    }

    @Test
    @DisplayName("ToString method → contains exception class name and message")
    void toStringMethod_ContainsExceptionClassNameAndMessage() {
        // Arrange
        final String message = "Custom message";
        InsolventException exception = new InsolventException(message);

        // Act
        String toStringResult = exception.toString();

        // Assert
        assertTrue(toStringResult.contains(InsolventException.class.getName()));
        assertTrue(toStringResult.contains(message));
    }
}

package com.bank.logic;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class SavingsAccountTest {

    private SavingsAccount account;
    private final double INITIAL_BALANCE = 1000.0;
    private final double CUSTOM_RATE = 0.05;

    @BeforeEach
    void setUp() {
        account = new SavingsAccount(INITIAL_BALANCE);
    }

    @Test
    @DisplayName("Constructor with single argument → Sets default interest rate and records history")
    void constructorSingleArg_ShouldSetDefaultRate() {
        // Arrange & Act (done in @BeforeEach)

        // Assert
        assertEquals(INITIAL_BALANCE, account.getBalance());
        assertEquals(0.02, account.getInterestRate(), "Should use DEFAULT_INTEREST_RATE");
        assertEquals(1, account.getHistory().size());
        assertTrue(account.getHistory().get(0).contains("Account opened with: " + INITIAL_BALANCE));
    }

    @Test
    @DisplayName("Constructor with two arguments → Sets custom rate and balance")
    void constructorTwoArgs_ShouldSetCustomValues() {
        // Arrange & Act
        SavingsAccount customAccount = new SavingsAccount(500.0, CUSTOM_RATE);

        // Assert
        assertEquals(500.0, customAccount.getBalance());
        assertEquals(CUSTOM_RATE, customAccount.getInterestRate());
        assertEquals(1, customAccount.getHistory().size());
    }

    @ParameterizedTest
    @CsvSource({
        "-1.0, 0.02",  // Negative balance
        "100.0, -0.01", // Negative interest rate
        "-1.0, -0.01"   // Both negative
    })
    @DisplayName("Constructor with invalid inputs → throws IllegalArgumentException")
    void constructorInvalidInputs_ShouldThrowException(double balance, double rate) {
        // Act & Assert
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, 
            () -> new SavingsAccount(balance, rate));
        assertEquals("Invalid initial values", ex.getMessage());
    }

    @Test
    @DisplayName("Process transaction with positive amount → increases balance")
    void processTransaction_PositiveAmount_ShouldIncreaseBalance() {
        // Arrange
        double deposit = 500.0;

        // Act
        account.processTransaction(deposit);

        // Assert
        assertEquals(INITIAL_BALANCE + deposit, account.getBalance());
    }

    @Test
    @DisplayName("Process transaction with negative amount within balance → decreases balance")
    void processTransaction_NegativeAmountWithinBalance_ShouldDecreaseBalance() {
        // Arrange
        double withdrawal = -200.0;

        // Act
        account.processTransaction(withdrawal);

        // Assert
        assertEquals(INITIAL_BALANCE + withdrawal, account.getBalance());
    }

    @Test
    @DisplayName("Process transaction exceeding balance → throws InsolventException")
    void processTransaction_ExceedingBalance_ShouldThrowInsolventException() {
        // Arrange
        double overdraw = -(INITIAL_BALANCE + 1.0);

        // Act & Assert
        InsolventException ex = assertThrows(InsolventException.class, 
            () -> account.processTransaction(overdraw));
        assertTrue(ex.getMessage().contains("Insufficient balance: " + overdraw));
    }

    @Test
    @DisplayName("Process transaction exactly equals balance → balance becomes zero")
    void processTransaction_ExactBalance_ShouldSucceed() {
        // Act & Assert
        assertDoesNotThrow(() -> account.processTransaction(-INITIAL_BALANCE));
        assertEquals(0.0, account.getBalance());
    }

    @Test
    @DisplayName("Apply interest → increases balance and adds to history")
    void applyInterest_ShouldIncreaseBalanceAndRecordHistory() {
        // Arrange
        SavingsAccount customAccount = new SavingsAccount(1000.0, 0.10); // 10%

        // Act
        customAccount.applyInterest();

        // Assert
        assertEquals(1100.0, customAccount.getBalance());
        List<String> history = customAccount.getHistory();
        assertEquals(2, history.size()); // Open + Interest
        assertTrue(history.get(1).contains("Interest applied: 100.00"));
    }

    @Test
    @DisplayName("Apply interest with zero balance → balance remains zero")
    void applyInterest_ZeroBalance_ShouldRemainZero() {
        // Arrange
        SavingsAccount zeroAccount = new SavingsAccount(0.0);

        // Act
        zeroAccount.applyInterest();

        // Assert
        assertEquals(0.0, zeroAccount.getBalance());
    }

    @Test
    @DisplayName("Get account summary → returns formatted string with current state")
    void getAccountSummary_ShouldReturnCorrectFormat() {
        // Arrange
        account.processTransaction(200.0); // Total 1200.0

        // Act
        String summary = account.getAccountSummary();

        // Assert
        // Balance: 1200.00 | Transactions: 1 (Note: history only grows on open and interest, 
        // and processTransaction does NOT add to history in source code provided)
        assertEquals("Balance: 1200.00 | Transactions: 1", summary);
    }

    @Test
    @DisplayName("Get history → returns an unmodifiable copy of history")
    void getHistory_ShouldReturnImmutableCopy() {
        // Act
        List<String> history = account.getHistory();

        // Assert
        assertThrows(UnsupportedOperationException.class, () -> history.add("Fake entry"));
    }

    @Test
    @DisplayName("ToString → returns correct string representation")
    void toString_ShouldReturnFormattedString() {
        // Act
        String result = account.toString();

        // Assert
        assertTrue(result.contains("balance=" + INITIAL_BALANCE));
        assertTrue(result.contains("interestRate=" + 0.02));
        assertTrue(result.startsWith("SavingsAccount{"));
    }
}

