        assertEquals(initialBalance, account.getBalance());
        assertEquals(customRate, account.getInterestRate());
        assertEquals(1, account.getHistory().size());
        assertTrue(account.getHistory().get(0).contains("Account opened with: " + initialBalance));
    }

    @ParameterizedTest
    @CsvSource({
        "-1.0, 0.05",  // Negative balance
        "100.0, -0.01", // Negative rate
        "-10.0, -0.05"  // Both negative
    })
    @DisplayName("Constructor with negative values → throws IllegalArgumentException")
