        // Act & Assert
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, 
            () -> new SavingsAccount(balance, rate));
        assertEquals("Invalid initial values", exception.getMessage());
    }

    @Test
    @DisplayName("processTransaction with positive amount → increases balance")
    void testProcessTransactionDeposit() {
        // Arrange
        double depositAmount = 500.0;
        double expectedBalance = initialBalance + depositAmount;

        // Act
        account.processTransaction(depositAmount);

        // Assert
        assertEquals(expectedBalance, account.getBalance());
    }

    @Test
    @DisplayName("processTransaction with negative amount within balance → decreases balance")
    void testProcessTransactionWithdrawal() {
        // Arrange
        double withdrawAmount = -200.0;
        double expectedBalance = initialBalance + withdrawAmount;

        // Act
        account.processTransaction(withdrawAmount);

        // Assert
        assertEquals(expectedBalance, account.getBalance());
    }

    @Test
    @DisplayName("processTransaction with amount 0 → balance remains unchanged")
    void testProcessTransactionZero() {
        // Act
        account.processTransaction(0.0);

        // Assert
        assertEquals(initialBalance, account.getBalance());
    }

    @Test
    @DisplayName("processTransaction exceeding balance → throws InsolventException")
    void testProcessTransactionInsolvent() {
        // Arrange
        double withdrawAmount = -(initialBalance + 1.0);

        // Act & Assert
        InsolventException exception = assertThrows(InsolventException.class, 
            () -> account.processTransaction(withdrawAmount));
        assertTrue(exception.getMessage().contains("Insufficient balance"));
        assertTrue(exception.getMessage().contains(String.valueOf(withdrawAmount)));
