        // Act
        account.applyInterest();

        // Assert
        assertEquals(expectedBalance, account.getBalance(), 0.001);
        List<String> history = account.getHistory();
        assertEquals(2, history.size());
        assertTrue(history.get(1).contains("Interest applied:"));
    }

    @Test
    @DisplayName("getAccountSummary → returns formatted balance and transaction count")
    void testGetAccountSummary() {
        // Arrange
        account.processTransaction(100.0); // history size becomes 2 (init + trans)

        // Act
        String summary = account.getAccountSummary();

        // Assert
        // Note: processTransaction does NOT add to history in original code, only constructor and applyInterest do.
        // Let's verify against actual provided source code behavior.
        // Source check: history.add is in constructor and applyInterest(). processTransaction is NOT.
        assertEquals(String.format("Balance: %.2f | Transactions: %d", 1100.0, 1), summary);
    }

    @Test
    @DisplayName("getHistory → returns immutable copy of history")
    void testGetHistoryImmutability() {
        // Arrange
        List<String> history = account.getHistory();

        // Act & Assert
        assertThrows(UnsupportedOperationException.class, () -> history.add("Fake entry"));
    }

    @Test
    @DisplayName("toString → returns correct string representation")
    void testToString() {
        // Act
        String result = account.toString();

        // Assert
        assertTrue(result.contains("SavingsAccount"));
        assertTrue(result.contains("balance=" + initialBalance));
        assertTrue(result.contains("interestRate=" + customRate));
    }

    @Test
    @DisplayName("Boundary check: processTransaction exactly equal to balance → success")
    void testProcessTransactionExactBalance() {
        // Arrange
        double withdrawAmount = -initialBalance;

        // Act & Assert
        assertDoesNotThrow(() -> account.processTransaction(withdrawAmount));
        assertEquals(0.0, account.getBalance());
    }
