package com.bank.logic;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.io.PrintStream;
import java.lang.reflect.Method;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Test class for Main.handleDeposit.
 * Since handleDeposit is private, we use Reflection to access it for unit testing.
 */
class MainTest {

    private final InputStream systemIn = System.in;
    private final PrintStream systemOut = System.out;
    private ByteArrayOutputStream testOut;

    private SavingsAccount account;
    private Method handleDepositMethod;

    @BeforeEach
    void setUp() throws NoSuchMethodException {
        // Setup output capture
        testOut = new ByteArrayOutputStream();
        System.setOut(new PrintStream(testOut));

        // Initial state: Account with 1000.0 as per Main.main() logic
        account = new SavingsAccount(1000.0);

        // Access private handleDeposit method via reflection
        handleDepositMethod = Main.class.getDeclaredMethod("handleDeposit", Scanner.class, SavingsAccount.class);
        handleDepositMethod.setAccessible(true);
    }

    @AfterEach
    void tearDown() {
        System.setOut(systemOut);
        System.setIn(systemIn);
    }

    private void invokeHandleDeposit(Scanner scanner) throws Exception {
        try {
            handleDepositMethod.invoke(null, scanner, account);
        } catch (java.lang.reflect.InvocationTargetException e) {
            // Unwrap the actual exception thrown by the method
            throw (Exception) e.getCause();
        }
    }

    @Test
    @DisplayName("Deposit valid positive amount → Balance increases and success message printed")
    void testHandleDepositValidAmount() throws Exception {
        // Arrange
        double depositAmount = 500.0;
        String input = depositAmount + "\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        double initialBalance = 1000.0;

        // Act
        invokeHandleDeposit(scanner);

        // Assert
        // Assuming SavingsAccount has a way to check balance or accountSummary
        assertTrue(account.getAccountSummary().contains("1500.0"), "Balance should be 1500.0");
        assertTrue(testOut.toString().contains("Deposit successful."), "Should print success message");
    }

    @ParameterizedTest
    @ValueSource(doubles = {0.0, -1.0, -100.50})
    @DisplayName("Deposit zero or negative amount → Balance remains unchanged and error message printed")
    void testHandleDepositInvalidAmounts(double amount) throws Exception {
        // Arrange
        String input = amount + "\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        double initialBalance = 1000.0;

        // Act
        invokeHandleDeposit(scanner);

        // Assert
        assertTrue(account.getAccountSummary().contains("1000.0"), "Balance should remain 1000.0");
        assertTrue(testOut.toString().contains("Amount must be positive."), "Should print positive amount error");
        assertFalse(testOut.toString().contains("Deposit successful."), "Should not print success message");
    }

    @Test
    @DisplayName("Deposit with non-numeric input followed by valid input → Eventually processes deposit")
    void testHandleDepositInvalidInputRecovery() throws Exception {
        // Arrange
        // "abc" is invalid, "xyz" is invalid, "200.0" is valid
        String input = "abc\nxyz\n200.0\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));

        // Act
        invokeHandleDeposit(scanner);

        // Assert
        assertTrue(testOut.toString().contains("Invalid input. Please enter a valid number."), 
                   "Should notify user of invalid input");
        assertTrue(account.getAccountSummary().contains("1200.0"), "Balance should be 1200.0 after recovery");
        assertTrue(testOut.toString().contains("Deposit successful."), "Should eventually succeed");
    }

    @Test
    @DisplayName("Deposit very large amount → Processed successfully")
    void testHandleDepositLargeAmount() throws Exception {
        // Arrange
        double largeAmount = 1_000_000.0;
        String input = largeAmount + "\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));

        // Act
        invokeHandleDeposit(scanner);

        // Assert
        assertTrue(account.getAccountSummary().contains("1001000.0"));
        assertTrue(testOut.toString().contains("Deposit successful."));
    }
}

