import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class MainTest {

    private final InputStream systemIn = System.in;
    private final PrintStream systemOut = System.out;
    private ByteArrayOutputStream outputStreamCaptor;

    @BeforeEach
    void setUp() {
        outputStreamCaptor = new ByteArrayOutputStream();
        System.setOut(new PrintStream(outputStreamCaptor));
    }

    @AfterEach
    void tearDown() {
        System.setIn(systemIn);
        System.setOut(systemOut);
    }

    /**
     * Helper to invoke the private handleWithdraw method via reflection.
     */
    private void invokeHandleWithdraw(Scanner scanner, SavingsAccount account) throws Exception {
        Method method = Main.class.getDeclaredMethod("handleWithdraw", Scanner.class, SavingsAccount.class);
        method.setAccessible(true);
        try {
            method.invoke(null, scanner, account);
        } catch (java.lang.reflect.InvocationTargetException e) {
            if (e.getCause() instanceof InsolventException) {
                throw (InsolventException) e.getCause();
            }
            throw (Exception) e.getCause();
        }
    }

    @Test
    @DisplayName("Withdraw positive amount within balance → Success")
    void testHandleWithdrawSuccess() throws Exception {
        // Arrange
        SavingsAccount mockAccount = mock(SavingsAccount.class);
        String input = "50.0\n";
        Scanner scanner = new Scanner(input);
        double amount = 50.0;

        // Act
        assertDoesNotThrow(() -> invokeHandleWithdraw(scanner, mockAccount));

        // Assert
        verify(mockAccount).processTransaction(-amount);
        assertTrue(outputStreamCaptor.toString().contains("Withdrawal successful."));
    }

    @Test
    @DisplayName("Withdraw zero amount → Prints amount must be positive")
    void testHandleWithdrawZeroAmount() throws Exception {
        // Arrange
        SavingsAccount mockAccount = mock(SavingsAccount.class);
        String input = "0\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleWithdraw(scanner, mockAccount);

        // Assert
        verify(mockAccount, never()).processTransaction(anyDouble());
        assertTrue(outputStreamCaptor.toString().contains("Amount must be positive."));
    }

    @Test
    @DisplayName("Withdraw negative amount → Prints amount must be positive")
    void testHandleWithdrawNegativeAmount() throws Exception {
        // Arrange
        SavingsAccount mockAccount = mock(SavingsAccount.class);
        String input = "-10.0\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleWithdraw(scanner, mockAccount);

        // Assert
        verify(mockAccount, never()).processTransaction(anyDouble());
        assertTrue(outputStreamCaptor.toString().contains("Amount must be positive."));
    }

    @Test
    @DisplayName("Withdraw amount exceeding balance → Throws InsolventException")
    void testHandleWithdrawInsolvent() throws Exception {
        // Arrange
        SavingsAccount mockAccount = mock(SavingsAccount.class);
        String input = "2000.0\n";
        Scanner scanner = new Scanner(input);

        doThrow(new InsolventException("Insufficient funds"))
            .when(mockAccount).processTransaction(-2000.0);

        // Act & Assert
        assertThrows(InsolventException.class, () -> invokeHandleWithdraw(scanner, mockAccount));
    }

    @Test
    @DisplayName("Invalid non-numeric input → Prompts again until valid double provided")
    void testHandleWithdrawInvalidInputThenSuccess() throws Exception {
        // Arrange
        SavingsAccount mockAccount = mock(SavingsAccount.class);
        // First input is text (invalid), second is negative (logic invalid), third is valid
        String input = "abc\n-5.0\n100.0\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleWithdraw(scanner, mockAccount);

        // Assert
        assertTrue(outputStreamCaptor.toString().contains("Invalid input. Please enter a valid number."));
        assertTrue(outputStreamCaptor.toString().contains("Amount must be positive."));
        assertTrue(outputStreamCaptor.toString().contains("Withdrawal successful."));
        verify(mockAccount).processTransaction(-100.0);
    }

    @Test
    @DisplayName("Withdraw extremely large amount → Success (if account permits)")
    void testHandleWithdrawLargeAmount() throws Exception {
        // Arrange
        SavingsAccount mockAccount = mock(SavingsAccount.class);
        double largeAmount = 1_000_000_000.0;
        String input = largeAmount + "\n";
        Scanner scanner = new Scanner(input);

        // Act
        invokeHandleWithdraw(scanner, mockAccount);

        // Assert
        verify(mockAccount).processTransaction(-largeAmount);
        assertTrue(outputStreamCaptor.toString().contains("Withdrawal successful."));
    }
}

package com.bank.logic;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.io.ByteArrayInputStream;
import java.io. lByteArrayOutputStream;
import java.io.InputStream;
import java.io.PrintStream;
import java.lang.reflect.Method;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.assertEquals;

/**
 * Test suite for Main class focusing on the private readInt method.
 * Since readInt is private, we use Reflection to access it for high-coverage unit testing.
 */
class MainTest {

    private final InputStream originalIn = System.in;
    private final PrintStream originalOut = System.out;
    private java.io.ByteArrayOutputStream outputStreamCaptor;

    @BeforeEach
    void setUp() {
        outputStreamCaptor = new java.io.ByteArrayOutputStream();
        System.setOut(new java.io.PrintStream(outputStreamCaptor));
    }

    @AfterEach
    void tearDown() {
        System.setIn(originalIn);
        System.setOut(originalOut);
    }

    /**
     * Helper to invoke the private readInt method via reflection.
     */
    private int invokeReadInt(Scanner scanner, String message) throws Exception {
        Method method = Main.class.getDeclaredMethod("readInt", Scanner.class, String.class);
        method.setAccessible(true);
        return (int) method.invoke(null, scanner, message);
    }

    @Test
    @DisplayName("readInt with valid integer input → returns the integer immediately")
    void testReadIntValidInput() throws Exception {
        // Arrange
        String input = "5\n";
        System.setIn(new ByteArrayInputStream(input.getBytes()));
        Scanner scanner = new Scanner(System.in);
        String prompt = "Choose an option: ";

        // Act
        int result = invokeReadInt(scanner, prompt);

        // Assert
        assertEquals(5, result, "The method should return the integer provided in the input stream.");
    }

    @Test
    @DisplayName("readInt with invalid string then valid integer → returns integer and logs error")
    void testReadIntInvalidThenValid() throws Exception {
        // Arrange
        // "abc" (invalid), "12.5" (invalid), "10" (valid)
        String input = "abc\n12.5\n10\n";
        System.setIn(new ByteArrayInputStream(input.getBytes()));
        Scanner scanner = new Scanner(System.in);
        String prompt = "Choose an option: ";

        // Act
        int result = invokeReadInt(scanner, prompt);

        // Assert
        assertEquals(10, result, "The method should eventually return the valid integer.");
        String output = outputStreamCaptor.toString();
        // Verify that the error message was printed for each invalid attempt
        int errorCount = (output.split("Invalid input. Please enter a number.").length) - 1;
        assertEquals(2, errorCount, "Should have printed invalid input message twice.");
    }

    @Test
    @DisplayName("readInt with boundary value (Integer.MAX_VALUE) → returns max integer")
    void testReadIntBoundaryMax() throws Exception {
        // Arrange
        String input = String.valueOf(Integer.MAX_VALUE) + "\n";
        System.setIn(new ByteArrayInputStream(input.getBytes()));
        Scanner scanner = new Scanner(System.in);

        // Act
        int result = invokeReadInt(scanner, "Prompt: ");

        // Assert
        assertEquals(Integer.MAX_VALUE, result);
    }

    @Test
    @DisplayName("readInt with boundary value (Integer.MIN_VALUE) → returns min integer")
    void testReadIntBoundaryMin() throws Exception {
        // Arrange
        String input = String.valueOf(Integer.MIN_VALUE) + "\n";
        System.setIn(new ByteArrayInputStream(input.getBytes()));
        Scanner scanner = new Scanner(System.in);

        // Act
        int result = invokeReadInt(scanner, "Prompt: ");

        // Assert
        assertEquals(Integer.MIN_VALUE, result);
    }

    @Test
    @DisplayName("readInt with empty input followed by valid integer → handles blank space and returns integer")
    void testReadIntWithWhitespace() throws Exception {
        // Arrange
        String input = "   \n  \n7\n";
        System.setIn(new ByteArrayInputStream(input.getBytes()));
        Scanner scanner = new Scanner(System.in);

        // Act
        int result = invokeReadInt(scanner, "Prompt: ");

        // Assert
        assertEquals(7, result);
    }
}

package com.bank.logic;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.io.PrintStream;
import java.lang.reflect.Method;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.*;

class MainTest {

    private final InputStream systemIn = System.in;
    private final PrintStream systemOut = System.out;
    private ByteArrayOutputStream outputStreamCaptor;

    @BeforeEach
    void setUp() {
        outputStreamCaptor = new ByteArrayOutputStream();
        System.setOut(new PrintStream(outputStreamCaptor));
    }

    @AfterEach
    void tearDown() {
        System.setIn(systemIn);
        System.setOut(systemOut);
    }

    /**
     * Helper method to invoke the private static readDouble method via reflection.
     */
    private double invokeReadDouble(Scanner scanner, String message) throws Exception {
        Method method = Main.class.getDeclaredMethod("readDouble", Scanner.class, String.class);
        method.setAccessible(true);
        return (double) method.invoke(null, scanner, message);
    }

    @Test
    @DisplayName("readDouble with valid double input → returns the double value")
    void readDoubleValidInput() throws Exception {
        // Arrange
        String input = "123.45\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        String message = "Enter amount: ";

        // Act
        double result = invokeReadDouble(scanner, message);

        // Assert
        assertEquals(123.45, result, 0.0001, "Should correctly parse positive double");
    }

    @Test
    @DisplayName("readDouble with integer input → returns double representation of the integer")
    void readDoubleIntegerInput() throws Exception {
        // Arrange
        String input = "500\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        String message = "Enter amount: ";

        // Act
        double result = invokeReadDouble(scanner, message);

        // Assert
        assertEquals(500.0, result, 0.0001, "Should treat integer input as double");
    }

    @Test
    @DisplayName("readDouble with negative double input → returns the negative value")
    void readDoubleNegativeInput() throws Exception {
        // Arrange
        String input = "-100.50\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        String message = "Enter amount: ";

        // Act
        double result = invokeReadDouble(scanner, message);

        // Assert
        assertEquals(-100.50, result, 0.0001, "Should correctly parse negative double");
    }

    @Test
    @DisplayName("readDouble with invalid string then valid double → prints error and returns double")
    void readDoubleInvalidThenValid() throws Exception {
        // Arrange
        // Sequence: "abc" (invalid), "xyz" (invalid), "75.25" (valid)
        String input = "abc\nxyz\n75.25\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        String message = "Enter amount: ";

        // Act
        double result = invokeReadDouble(scanner, message);

        // Assert
        assertEquals(75.25, result, 0.0001);
        String output = outputStreamCaptor.toString();

        // Verify that the error message was printed exactly twice
        int errorCount = (output.split("Invalid input. Please enter a valid number.").length) - 1;
        assertEquals(2, errorCount, "Should print invalid input message for every non-double entry");
    }

    @ParameterizedTest
    @ValueSource(strings = {"0.0", "1000000.99", "0.00001"})
    @DisplayName("readDouble with boundary and special values → returns correct double")
    void readDoubleBoundaryValues(String inputVal) throws Exception {
        // Arrange
        String input = inputVal + "\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        String message = "Test: ";

        // Act
        double result = invokeReadDouble(scanner, message);

        // Assert
        assertEquals(Double.parseDouble(inputVal), result, 0.0001);
    }

    @Test
    @DisplayName("readDouble with empty input/whitespace → prints error and waits for valid input")
    void readDoubleWhitespaceInput() throws Exception {
        // Arrange
        String input = "  \n\t\n42.0\n";
        Scanner scanner = new Scanner(new ByteArrayInputStream(input.getBytes()));
        String message = "Enter amount: ";

        // Act
        double result = invokeReadDouble(scanner, message);

        // Assert
        assertEquals(42.0, result, 0.0001);
        assertTrue(outputStreamCaptor.toString().contains("Invalid input. Please enter a valid number."));
    }
}

package com.bank.logic;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

/**
 * Unit tests for {@link InsolventException}.
 * This class ensures that the custom runtime exception correctly handles message passing 
 * and inherits the expected behavior from RuntimeException.
 */
class InsolventExceptionTest {

    @Test
    @DisplayName("Constructor with standard message → preserves the exact message string")
    void constructor_WithStandardMessage_ShouldSetMessage() {
        // Arrange
        String expectedMessage = "Insufficient funds for this transaction";

        // Act
        InsolventException exception = new InsolventException(expectedMessage);

        // Assert
        assertEquals(expectedMessage, exception.getMessage(), 
            "The exception message should match the value passed to the constructor");
    }

    @ParameterizedTest
    @ValueSource(strings = {"", " ", "\n", "\t", "Special characters: !@#$%^&*()"})
    @DisplayName("Constructor with edge case strings (empty, blank, special) → preserves input")
    void constructor_WithEdgeCaseMessages_ShouldPreserveInput(String edgeCaseMessage) {
        // Arrange - handled by ParameterizedTest source

        // Act
        InsolventException exception = new InsolventException(edgeCaseMessage);

        // Assert
        assertEquals(edgeCaseMessage, exception.getMessage(), 
            "The exception should handle boundary string values including empty and special characters");
    }

    @Test
    @DisplayName("Constructor with null message → sets message to null")
    void constructor_WithNullMessage_ShouldSetMessageToNull() {
        // Arrange
        String nullMessage = null;

        // Act
        InsolventException exception = new InsolventException(nullMessage);

        // Assert
        assertEquals(null, exception.getMessage(), 
            "The exception message should be null when null is passed to the constructor");
    }

    @Test
    @DisplayName("Throwing InsolventException → can be caught as RuntimeException")
    void throwInsolventException_ShouldBeCatchableAsRuntimeException() {
        // Arrange
        String message = "Account insolvent";

        // Act & Assert
        assertThrows(RuntimeException.class, () -> {
            throw new InsolventException(message);
        }, "InsolventException must be a subtype of RuntimeException");
    }
}
